type Value = any

type AxError struct {
	Category  string
	Type      string
	Message   string
	Status    int
	Code      string
	Retryable bool
	Payload   Value
}

func (e AxError) Error() string {
	if e.Message != "" {
		return e.Message
	}
	return e.Category
}

type SignatureError struct{ AxError }
type ValidationError struct{ AxError }
type AIServiceError struct{ AxError }

// coreFlow carries non-local exits (return/break/continue) out of core.try
// closures in emitted Core functions, mirroring the Rust runtime's CoreFlow
// enum. Raised errors travel through the closure's error result instead.
const (
	coreFlowNormal uint8 = iota
	coreFlowReturn
	coreFlowBreak
	coreFlowContinue
)

type coreFlow struct {
	kind  uint8
	value Value
}

// mustCore adapts an emitted Core function's (Value, error) result for hand
// call sites that signal failure by panicking; the panic is recovered into
// an error at the nearest safeValue boundary, exactly where the old
// panic-based raise surfaced.

var axirCoveragePath = os.Getenv("AXIR_COVERAGE_FILE")
var axirCoverageSeen sync.Map

func axirCoverageMark(name string) {
	if axirCoveragePath == "" {
		return
	}
	if _, loaded := axirCoverageSeen.LoadOrStore(name, true); loaded {
		return
	}
	handle, err := os.OpenFile(axirCoveragePath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return
	}
	defer handle.Close()
	_, _ = handle.WriteString(name + "\n")
}

func mustCore(value Value, err error) Value {
	if err != nil {
		panic(err)
	}
	return value
}

func Object(entries ...Value) map[string]Value {
	out := map[string]Value{}
	for i := 0; i+1 < len(entries); i += 2 {
		coreSet(out, entries[i], entries[i+1])
	}
	return out
}

func Array(items ...Value) []Value {
	return append([]Value(nil), items...)
}

type AxArray struct {
	Items []Value
}

// MarshalJSON serializes AxArray as a JSON array, not as the Go struct shape
// {"Items":[...]}. Without this, json.Marshal leaks the wrapper struct: an
// AxArray returned from a host callable (e.g. llmQuery) would cross into a JS
// runtime as an object, so the model's documented `string[]` indexing (`[0]`)
// would read undefined. The real-client request path normalizes via
// runtimeJSONValue and is unaffected; this only fixes raw json.Marshal sites.
func (a *AxArray) MarshalJSON() ([]byte, error) {
	if a == nil || a.Items == nil {
		return []byte("[]"), nil
	}
	return json.Marshal(a.Items)
}

func MutableArray(items ...Value) *AxArray {
	return &AxArray{Items: append([]Value(nil), items...)}
}

func asMap(value Value) map[string]Value {
	if value == nil {
		return map[string]Value{}
	}
	switch v := value.(type) {
	case map[string]any:
		out := map[string]Value{}
		for key, item := range v {
			coreSet(out, key, normalizeJSON(item))
		}
		return out
	case AxSignature:
		return v.toMap()
	case *AxSignature:
		if v == nil {
			return map[string]Value{}
		}
		return v.toMap()
	case Field:
		return v.toMap()
	case *Field:
		if v == nil {
			return map[string]Value{}
		}
		return v.toMap()
	case FieldType:
		return v.toMap()
	case *FieldType:
		if v == nil {
			return map[string]Value{}
		}
		return v.toMap()
	default:
		return map[string]Value{}
	}
}

func asSlice(value Value) []Value {
	if value == nil {
		return []Value{}
	}
	switch v := value.(type) {
	case *AxArray:
		if v == nil {
			return []Value{}
		}
		return v.Items
	case []any:
		return append([]Value(nil), v...)
	case []string:
		out := make([]Value, 0, len(v))
		for _, item := range v {
			out = append(out, item)
		}
		return out
	case []Field:
		out := make([]Value, 0, len(v))
		for _, item := range v {
			out = append(out, item)
		}
		return out
	case []*Field:
		out := make([]Value, 0, len(v))
		for _, item := range v {
			out = append(out, item)
		}
		return out
	default:
		return []Value{}
	}
}

func coreIter(value Value) []Value {
	if m, ok := value.(map[string]Value); ok {
		keys := orderedKeys(m)
		out := make([]Value, 0, len(keys))
		for _, key := range keys {
			if key != "__order" {
				out = append(out, key)
			}
		}
		return out
	}
	return asSlice(value)
}

func orderedKeys(m map[string]Value) []string {
	var out []string
	seen := map[string]bool{}
	for _, raw := range asSlice(m["__order"]) {
		key := display(raw)
		if key != "__order" && !seen[key] {
			if _, ok := m[key]; ok {
				out = append(out, key)
				seen[key] = true
			}
		}
	}
	for key := range m {
		if key != "__order" && !seen[key] {
			out = append(out, key)
		}
	}
	sort.Strings(out[len(seen):])
	return out
}

func coreGet(target Value, key Value, fallback Value) Value {
	k := display(key)
	switch v := target.(type) {
	case map[string]Value:
		if item, ok := v[k]; ok {
			return item
		}
		for _, alias := range keyAliases(k) {
			if item, ok := v[alias]; ok {
				return item
			}
		}
	case []Value:
		idx, ok := intIndex(key)
		if ok && idx >= 0 && idx < len(v) {
			return v[idx]
		}
	case *AxArray:
		idx, ok := intIndex(key)
		if v != nil && ok && idx >= 0 && idx < len(v.Items) {
			return v.Items[idx]
		}
	case AxSignature:
		return coreGet(v.toMap(), key, fallback)
	case *AxSignature:
		if v != nil {
			return coreGet(v.toMap(), key, fallback)
		}
	case Field:
		return coreGet(v.toMap(), key, fallback)
	case *Field:
		if v != nil {
			return coreGet(v.toMap(), key, fallback)
		}
	case FieldType:
		return coreGet(v.toMap(), key, fallback)
	case *FieldType:
		if v != nil {
			return coreGet(v.toMap(), key, fallback)
		}
	case *AxGen:
		return v.get(k, fallback)
	case *AxAgent:
		return v.get(k, fallback)
	case *AxFlow:
		if v != nil {
			switch k {
			case "state":
				return v.State
			case "steps":
				return coreGet(v.State, "steps", fallback)
			case "options":
				return v.Options
			case "chat_log", "chatLog":
				return coreGet(v.State, "chat_log", fallback)
			case "traces":
				return coreGet(v.State, "traces", fallback)
			case "usage":
				return coreGet(v.State, "usage", fallback)
			}
		}
	case CodeRuntime:
		if k == "language" {
			return v.Language()
		}
		if k == "usageInstructions" || k == "usage_instructions" {
			return v.UsageInstructions()
		}
	case Tool:
		return v.get(k, fallback)
	case *Tool:
		if v != nil {
			return v.get(k, fallback)
		}
	}
	return fallback
}

func keyAliases(key string) []string {
	switch key {
	case "is_array":
		return []string{"isArray"}
	case "is_optional":
		return []string{"isOptional"}
	case "is_internal":
		return []string{"isInternal"}
	case "is_cached":
		return []string{"isCached"}
	case "min_length":
		return []string{"minLength"}
	case "max_length":
		return []string{"maxLength"}
	case "pattern_description":
		return []string{"patternDescription"}
	case "input_fields":
		return []string{"inputs"}
	case "output_fields":
		return []string{"outputs"}
	default:
		return nil
	}
}

func coreSet(target Value, key Value, value Value) error {
	if m, ok := target.(map[string]Value); ok {
		k := display(key)
		if _, exists := m[k]; !exists {
			m["__order"] = coreAppend(m["__order"], k)
		}
		m[k] = value
		return nil
	}
	return AxError{Category: "runtime", Message: "core.set target must be a map"}
}

func coreAppend(target Value, value Value) Value {
	if a, ok := target.(*AxArray); ok {
		if a == nil {
			return MutableArray(value)
		}
		a.Items = append(a.Items, value)
		return a
	}
	return append(asSlice(target), value)
}

func coreTruthy(value Value) bool {
	switch v := value.(type) {
	case nil:
		return false
	case bool:
		return v
	case string:
		return v != ""
	case int:
		return v != 0
	case int64:
		return v != 0
	case float64:
		return v != 0
	case []Value:
		return len(v) > 0
	case *AxArray:
		return v != nil && len(v.Items) > 0
	case map[string]Value:
		return len(orderedKeys(v)) > 0
	default:
		return true
	}
}

func num(value Value) float64 {
	switch v := value.(type) {
	case nil:
		return 0
	case int:
		return float64(v)
	case int64:
		return float64(v)
	case float64:
		return v
	case bool:
		if v {
			return 1
		}
		return 0
	case string:
		n, _ := strconv.ParseFloat(v, 64)
		return n
	default:
		n, _ := strconv.ParseFloat(display(v), 64)
		return n
	}
}

func intIndex(value Value) (int, bool) {
	switch v := value.(type) {
	case int:
		return v, true
	case int64:
		return int(v), true
	case float64:
		return int(v), true
	default:
		return 0, false
	}
}

func display(value Value) string {
	switch v := value.(type) {
	case nil:
		return ""
	case string:
		return v
	case bool:
		if v {
			return "true"
		}
		return "false"
	case int:
		return strconv.Itoa(v)
	case int64:
		return strconv.FormatInt(v, 10)
	case float64:
		if math.Trunc(v) == v {
			return strconv.FormatInt(int64(v), 10)
		}
		return strconv.FormatFloat(v, 'f', -1, 64)
	case AxError:
		return v.Error()
	case error:
		return v.Error()
	case *AxArray:
		return stableStringify(v)
	default:
		return fmt.Sprint(v)
	}
}

func canonical(value Value) Value {
	switch v := value.(type) {
	case *AxArray:
		if v == nil {
			return []Value{}
		}
		out := make([]Value, 0, len(v.Items))
		for _, item := range v.Items {
			out = append(out, canonical(item))
		}
		return out
	case map[string]Value:
		out := map[string]Value{}
		for _, key := range orderedKeys(v) {
			if key == "__order" {
				continue
			}
			out[key] = canonical(v[key])
		}
		return out
	case []Value:
		out := make([]Value, 0, len(v))
		for _, item := range v {
			out = append(out, canonical(item))
		}
		return out
	case float64:
		if math.Trunc(v) == v {
			return int64(v)
		}
		return v
	default:
		return v
	}
}

func equal(left Value, right Value) bool {
	return stableStringify(canonical(left)) == stableStringify(canonical(right))
}

func stableStringify(value Value) string {
	var b strings.Builder
	writeStableJSON(&b, value)
	return b.String()
}

func writeStableJSON(b *strings.Builder, value Value) {
	switch v := value.(type) {
	case nil:
		b.WriteString("null")
	case string:
		b.WriteString(strconv.Quote(v))
	case bool:
		if v {
			b.WriteString("true")
		} else {
			b.WriteString("false")
		}
	case int:
		b.WriteString(strconv.Itoa(v))
	case int64:
		b.WriteString(strconv.FormatInt(v, 10))
	case float64:
		b.WriteString(strconv.FormatFloat(v, 'f', -1, 64))
	case []Value:
		b.WriteByte('[')
		for i, item := range v {
			if i > 0 {
				b.WriteByte(',')
			}
			writeStableJSON(b, item)
		}
		b.WriteByte(']')
	case *AxArray:
		writeStableJSON(b, asSlice(v))
	case map[string]Value:
		b.WriteByte('{')
		keys := sortedMapKeys(v)
		first := true
		for _, key := range keys {
			if key == "__order" {
				continue
			}
			if !first {
				b.WriteByte(',')
			}
			first = false
			b.WriteString(strconv.Quote(key))
			b.WriteByte(':')
			writeStableJSON(b, v[key])
		}
		b.WriteByte('}')
	default:
		data, _ := json.Marshal(v)
		b.Write(data)
	}
}

func sortedMapKeys(m map[string]Value) []string {
	keys := make([]string, 0, len(m))
	for key := range m {
		if key != "__order" {
			keys = append(keys, key)
		}
	}
	sort.Strings(keys)
	return keys
}

func parseJSONErr(text string) (Value, error) {
	dec := json.NewDecoder(strings.NewReader(text))
	raw, err := parseJSONValue(dec)
	if err != nil {
		return nil, AxError{Category: "runtime", Message: err.Error()}
	}
	return raw, nil
}

func parseJSON(text string) Value { return mustCore(parseJSONErr(text)) }

func ParseJSON(text string) Value { return parseJSON(text) }

func parseJSONValue(dec *json.Decoder) (Value, error) {
	tok, err := dec.Token()
	if err != nil {
		return nil, err
	}
	switch v := tok.(type) {
	case json.Delim:
		switch v {
		case '{':
			out := map[string]Value{}
			for dec.More() {
				keyTok, err := dec.Token()
				if err != nil {
					return nil, err
				}
				value, err := parseJSONValue(dec)
				if err != nil {
					return nil, err
				}
				coreSet(out, display(keyTok), value)
			}
			_, err := dec.Token()
			return out, err
		case '[':
			out := []Value{}
			for dec.More() {
				value, err := parseJSONValue(dec)
				if err != nil {
					return nil, err
				}
				out = append(out, value)
			}
			_, err := dec.Token()
			return out, err
		default:
			return nil, fmt.Errorf("unexpected JSON delimiter %q", v)
		}
	default:
		return normalizeJSON(v), nil
	}
}

func normalizeJSON(value any) Value {
	switch v := value.(type) {
	case map[string]any:
		out := map[string]Value{}
		for key, item := range v {
			coreSet(out, key, normalizeJSON(item))
		}
		return out
	case []any:
		out := make([]Value, 0, len(v))
		for _, item := range v {
			out = append(out, normalizeJSON(item))
		}
		return out
	default:
		return v
	}
}

func runtimeJSONValue(value Value) any {
	switch v := value.(type) {
	case map[string]Value:
		out := map[string]any{}
		for _, key := range orderedKeys(v) {
			if key != "__order" {
				out[key] = runtimeJSONValue(v[key])
			}
		}
		return out
	case []Value:
		out := make([]any, 0, len(v))
		for _, item := range v {
			out = append(out, runtimeJSONValue(item))
		}
		return out
	case *AxArray:
		return runtimeJSONValue(asSlice(v))
	default:
		return v
	}
}

func errorValue(raw any) Value {
	switch v := raw.(type) {
	case AxError:
		return Object("__error", v.Category, "message", v.Message, "__type", v.Type, "status", float64(v.Status), "code", v.Code, "retryable", v.Retryable)
	case error:
		return Object("__error", "runtime", "message", v.Error())
	default:
		return Object("__error", "runtime", "message", display(v))
	}
}

func asAxError(value Value) AxError {
	if err, ok := value.(AxError); ok {
		return err
	}
	m := asMap(value)
	if cat := display(m["__error"]); cat != "" {
		return AxError{Category: cat, Message: display(m["message"]), Type: display(m["__type"]), Status: int(num(m["status"])), Code: display(m["code"]), Retryable: coreTruthy(m["retryable"]), Payload: m["payload"]}
	}
	return AxError{Category: "runtime", Message: display(value)}
}

func coreRegexMatch(pattern Value, value Value) Value {
	return regexp.MustCompile(display(pattern)).FindStringIndex(display(value)) != nil
}

func coreStringTrim(value Value) Value { return strings.TrimSpace(display(value)) }

func coreTypeIs(value Value, typeName Value) Value {
	switch display(typeName) {
	case "object":
		_, ok := value.(map[string]Value)
		return ok
	case "list":
		if _, ok := value.([]Value); ok {
			return true
		}
		_, ok := value.(*AxArray)
		return ok
	case "string":
		_, ok := value.(string)
		return ok
	case "number":
		_, ok := value.(float64)
		if ok {
			return true
		}
		_, ok = value.(int)
		return ok
	case "boolean":
		_, ok := value.(bool)
		return ok
	case "null":
		return value == nil
	case "json":
		return true
	default:
		return false
	}
}

func _core_not(value Value) Value             { return !coreTruthy(value) }
func _core_and(left Value, right Value) Value { return coreTruthy(left) && coreTruthy(right) }
func _core_or(left Value, right Value) Value  { return coreTruthy(left) || coreTruthy(right) }
func _core_eq(left Value, right Value) Value  { return equal(left, right) }
func _core_ne(left Value, right Value) Value  { return !equal(left, right) }
func _core_lt(left Value, right Value) Value  { return num(left) < num(right) }
func _core_lte(left Value, right Value) Value { return num(left) <= num(right) }
func _core_gt(left Value, right Value) Value  { return num(left) > num(right) }
func _core_gte(left Value, right Value) Value { return num(left) >= num(right) }
func _core_add(left Value, right Value) Value {
	if _, ok := left.(string); ok {
		return display(left) + display(right)
	}
	if _, ok := right.(string); ok {
		return display(left) + display(right)
	}
	return num(left) + num(right)
}
func _core_mul(left Value, right Value) Value { return num(left) * num(right) }
func _core_div(left Value, right Value) Value {
	d := num(right)
	if d == 0 {
		d = 1
	}
	return num(left) / d
}
func _core_contains(container Value, item Value) Value {
	if m, ok := container.(map[string]Value); ok {
		_, ok := m[display(item)]
		return ok
	}
	for _, v := range asSlice(container) {
		if equal(v, item) {
			return true
		}
	}
	if _, ok := container.(string); ok {
		needle := display(item)
		return needle != "" && strings.Contains(display(container), needle)
	}
	return false
}
func _core_len(value Value) Value {
	switch v := value.(type) {
	case string:
		return float64(len(v))
	case []Value:
		return float64(len(v))
	case *AxArray:
		if v == nil {
			return float64(0)
		}
		return float64(len(v.Items))
	case map[string]Value:
		return float64(len(orderedKeys(v)))
	default:
		return float64(0)
	}
}
func _core_truthy(value Value) Value      { return coreTruthy(value) }
func _core_is_none(value Value) Value     { return value == nil }
func _core_is_not_none(value Value) Value { return value != nil }
func _core_none() Value                   { return nil }
func _core_coalesce(value Value, fallback Value) Value {
	if value == nil {
		return fallback
	}
	return value
}
func _core_map_merge(left Value, right Value) Value {
	out := cloneMap(asMap(left))
	for _, k := range orderedKeys(asMap(right)) {
		coreSet(out, k, coreGet(right, k, nil))
	}
	return out
}
func _core_map_contains(values Value, key Value) Value {
	m := asMap(values)
	k := display(key)
	if _, ok := m[k]; ok {
		return true
	}
	for _, alias := range keyAliases(k) {
		if _, ok := m[alias]; ok {
			return true
		}
	}
	return false
}
func _core_map_get(values Value, key Value) Value { return coreGet(values, key, nil) }
func _core_map_delete(values Value, key Value) Value {
	if m, ok := values.(map[string]Value); ok {
		delete(m, display(key))
		return m
	}
	out := cloneMap(asMap(values))
	delete(out, display(key))
	return out
}
func _core_map_update(target Value, values Value) Value {
	out := cloneMap(asMap(target))
	for _, k := range orderedKeys(asMap(values)) {
		coreSet(out, k, coreGet(values, k, nil))
	}
	return out
}
func _core_map_keys(values Value) Value {
	out := Array()
	for _, k := range orderedKeys(asMap(values)) {
		out = append(out, k)
	}
	return out
}
func _core_map_values(values Value) Value {
	out := Array()
	for _, k := range orderedKeys(asMap(values)) {
		out = append(out, coreGet(values, k, nil))
	}
	return out
}
func _core_record_new(name Value, values Value) Value { return recordNew(display(name), asMap(values)) }
func _core_object_call_method(target Value, methodName Value, arg Value) (Value, error) {
	return objectCallMethod(target, display(methodName), arg)
}
func _core_program_components(program Value) Value {
	if p, ok := program.(AxProgram); ok {
		return p.GetOptimizableComponents()
	}
	return Array()
}
func _core_program_apply_components(program Value, componentMap Value) Value {
	if p, ok := program.(AxProgram); ok {
		p.ApplyOptimizedComponents(asMap(componentMap))
	}
	return Object()
}
func _core_ai_complete_once(client Value, request Value) (Value, error) {
	if c, ok := client.(AIClient); ok {
		out, err := c.Chat(context.Background(), asMap(request), Object())
		if err != nil {
			return nil, err
		}
		return chat_response_to_completion(out)
	}
	return nil, AxError{Category: "runtime", Message: "client does not implement AIClient"}
}
func _core_retry_sleep(attempt Value) Value   { return nil }
func _core_exception_message(err Value) Value { return display(coreGet(err, "message", err)) }
