	var v_seen Value
	var v_trimmed Value
	var v_unique Value
	if len(args) > 0 { v_playbook = args[0] }
	_ = v_playbook
	_ = v_bullet
	_ = v_bullet_harmful
	_ = v_bullet_helpful
	_ = v_bullet_updated_at
	_ = v_bullets
	_ = v_content
	_ = v_empty_map
