func (a *AxAgent) GetOptimizableComponents() Value {
	components := Array()
	for _, item := range asSlice(a.Distiller.GetOptimizableComponents()) {
		components = append(components, item)
	}
	for _, item := range asSlice(a.Executor.GetOptimizableComponents()) {
		components = append(components, item)
	}
	for _, item := range asSlice(a.Responder.GetOptimizableComponents()) {
		components = append(components, item)
	}
	runtime := coreGet(a.State, "runtime_contract", Object("language", "javascript", "code_field", "javascriptCode"))
	policy := coreGet(a.State, "policy", mustCore(_agent_policy_registry(Object())))
	components = append(components, mustCore(_optimization_component("root.agent.runtime", "root.agent", "runtime-policy", runtime, "Agent runtime-language metadata and code-field policy.", Array("Keep code field names aligned with the selected runtime language."), Array(), true, "json", Object("component", "runtime_contract"))))
	components = append(components, mustCore(_optimization_component("root.agent.policy", "root.agent", "agent-policy", policy, "Actor primitive, discovery, delegation, and prompt placement policy.", Array("Do not expose protocol-only actions as actor primitives."), Array("root.agent.runtime"), true, "json", Object("component", "policy_registry"))))
	return components
}
func (a *AxAgent) ApplyOptimizedComponents(m map[string]Value) {
	a.Distiller.ApplyOptimizedComponents(m)
	a.Executor.ApplyOptimizedComponents(m)
	a.Responder.ApplyOptimizedComponents(m)
	if value := coreGet(m, "root.agent.runtime", nil); value != nil {
		coreSet(a.State, "runtime_contract", value)
	}
	if value := coreGet(m, "root.agent.policy", nil); value != nil {
		coreSet(a.State, "policy", value)
	}
}
func (a *AxAgent) ApplyOptimization(artifact Value) {
	components := a.GetOptimizableComponents()
	var validated Value
	if text, ok := artifact.(string); ok {
		validated = mustCore(_deserialize_optimized_artifact(text, components))
	} else {
		if artifact == nil {
			artifact = Object()
		}
		validated = mustCore(_validate_optimized_artifact(artifact, components))
	}
	a.ApplyOptimizedComponents(asMap(coreGet(validated, "componentMap", Object())))
}
func scoreOptimizationPrediction(task map[string]Value, prediction Value, options map[string]Value) (Value, Value) {
	opts := options
	if opts == nil {
		opts = Object()
	}
	var rawScores Value
	if value, ok := task["metric_score"]; ok {
		rawScores = value
	} else if value, ok := task["scores"]; ok {
		rawScores = value
	} else if value, ok := task["score"]; ok {
		rawScores = value
	} else if display(coreGet(prediction, "completionType", nil)) == "error" {
		rawScores = float64(0)
	} else {
		rawScores = float64(1)
	}
	scores := mustCore(_normalize_optimization_metric_scores(rawScores))
	scalar := mustCore(_scalarize_optimization_scores(scores, opts))
	scalar = mustCore(_adjust_optimization_score_for_actions(scalar, task, prediction))
	return scores, scalar
}
func agentClarificationFromError(err error) (Value, bool) {
	ax, ok := err.(AxError)
	if !ok || ax.Category != "clarification" {
		return nil, false
	}
	clarification := ax.Payload
	if args := asSlice(coreGet(ax.Payload, "args", Array())); len(args) > 0 {
		clarification = args[0]
	}
	return clarification, true
}
func (a *AxAgent) EvaluateOptimizationTask(client AIClient, task map[string]Value, options map[string]Value) Value {
	opts := options
	if opts == nil {
		opts = Object()
	}
	input := coreGet(task, "input", nil)
	if !coreTruthy(input) {
		input = task
	}
	output, err := a.Forward(context.Background(), client, asMap(input), asMap(coreGet(opts, "forward_options", Object())))
	if err == nil {
		return mustCore(_build_agent_eval_prediction(output, a.GetActionLog(), a.GetUsage(), a.ExportTrace()))
	}
	if clarification, ok := agentClarificationFromError(err); ok {
		return Object("completionType", "askClarification", "clarification", clarification, "actionLog", a.GetActionLog(), "functionCalls", coreGet(a.State, "function_call_traces", Array()), "toolErrors", Array(), "turnCount", float64(0), "usage", a.GetUsage(), "trace", a.ExportTrace())
	}
	return Object("completionType", "error", "error", Object("message", err.Error()), "actionLog", a.GetActionLog(), "functionCalls", coreGet(a.State, "function_call_traces", Array()), "toolErrors", Array(err.Error()), "turnCount", float64(0), "usage", a.GetUsage(), "trace", a.ExportTrace())
}
func (a *AxAgent) EvaluateOptimization(client AIClient, dataset Value, candidateMap map[string]Value, options map[string]Value) Value {
	opts := options
	if opts == nil {
		opts = Object()
	}
	normalized := asMap(mustCore(_normalize_optimization_dataset(dataset)))
	rows := MutableArray()
	original := asMap(mustCore(_optimization_component_current_map(a.GetOptimizableComponents())))
	candidate := cloneMap(candidateMap)
	phase := coreGet(opts, "phase", "train")
	maxMetricCalls := int(num(coreGet(opts, "maxMetricCalls", coreGet(opts, "max_metric_calls", float64(1000000000)))))
	calls := 0
	defer a.ApplyOptimizedComponents(original)
	if coreTruthy(candidate) {
		a.ApplyOptimizedComponents(candidate)
	}
	for _, rawTask := range asSlice(coreGet(normalized, "train", Array())) {
		if calls >= maxMetricCalls {
			panic(AxError{Category: "runtime", Message: fmt.Sprintf("max metric calls exceeded: %d", maxMetricCalls)})
		}
		calls++
		task, isMap := rawTask.(map[string]Value)
		if !isMap {
			task = Object("input", rawTask)
		}
		prediction := a.EvaluateOptimizationTask(client, task, opts)
		errVal := coreGet(prediction, "error", nil)
		scoreTask := task
		if !isMap {
			scoreTask = Object()
		}
		scores, scalar := scoreOptimizationPrediction(scoreTask, prediction, opts)
		rows = coreAppend(rows, mustCore(_build_optimization_eval_row(rawTask, prediction, scores, scalar, coreGet(prediction, "trace", nil), errVal))).(*AxArray)
	}
	return mustCore(_build_optimization_eval_result(rows, candidate, phase))
}

// Playbook builds an evolving context AxPlaybook bound to an agent stage (the
// actor/task stage by default; pass "target":"responder" for the responder).
// As the playbook evolves it is injected into the live stage prompt unless
// "apply" is false. The evolution engine (ACE) is an implementation detail.
func (a *AxAgent) Playbook(options map[string]Value) *AxPlaybook {
	if options == nil {
		options = Object()
	}
	target := display(coreGet(options, "target", "actor"))
	student := playbookOption(options, "studentAI", "student_ai", "student", "client", "ai")
	if student == nil {
		student = coreGet(a.Options, "ai", coreGet(a.Options, "client", nil))
	}
	if playbookClient(student) == nil {
		panic(AxError{Category: "optimize", Message: "AxAgent.Playbook(): studentAI is required when the agent has no default ai."})
	}
	stage := a.Executor
	if target == "responder" {
		stage = a.Responder
	}
	handleOptions := cloneMap(options)
	coreSet(handleOptions, "studentAI", student)
	handle := Playbook(stage, handleOptions)
	if coreGet(options, "apply", nil) == false {
		handle.SetApplyHook(func(string) {})
		return handle
	}
	base := stage.Signature.Description
	handle.SetApplyHook(func(rendered string) {
		stage.Signature.Description = playbookComposeInstruction(base, rendered)
	})
	return handle
}

type axAgentOptimizerEvaluator struct {
	agent   *AxAgent
	client  AIClient
	dataset Value
	options map[string]Value
}

func (e *axAgentOptimizerEvaluator) Evaluate(candidateMap map[string]Value, options map[string]Value) (Value, error) {
	return safeValue(func() Value {
		merged := cloneMap(e.options)
		for key, value := range options {
			if key != "__order" {
				coreSet(merged, key, value)
			}
		}
		evalDataset := coreGet(merged, "dataset", coreGet(merged, "_dataset", e.dataset))
		if evalDataset == nil {
			evalDataset = e.dataset
		}
		return e.agent.EvaluateOptimization(e.client, evalDataset, candidateMap, merged)
	})
}

// OptimizeWith runs the supplied optimizer engine against the agent's
// optimizable components. When options carry a live client ("client"/"ai") the
// evaluator drives real agent rollouts; otherwise the engine runs without one.
// The normalized artifact is applied unless options["apply"] is false.
func (a *AxAgent) OptimizeWith(engine OptimizerEngine, dataset Value, options map[string]Value) (Value, error) {
	return safeValue(func() Value {
		opts := options
		if opts == nil {
			opts = Object()
		}
		components := a.GetOptimizableComponents()
		client := playbookClient(coreGet(opts, "client", coreGet(opts, "ai", nil)))
		if dataset == nil {
			dataset = Array()
		}
		run := asMap(mustCore(_prepare_optimizer_run("axagent", components, dataset, opts, a.ExportTrace(), client != nil)))
		request := asMap(coreGet(run, "request", Object()))
		var evaluator OptimizerEvaluator
		if client != nil {
			evaluator = &axAgentOptimizerEvaluator{agent: a, client: client, dataset: dataset, options: opts}
		}
		response, err := engine.Optimize(request, evaluator)
		if err != nil {
			panic(err)
		}
		artifact := mustCore(_normalize_optimizer_engine_response(response, coreGet(response, "optimizerName", "optimizer"), coreGet(response, "optimizerVersion", "host"), components))
		if coreGet(opts, "apply", true) != false {
			a.ApplyOptimization(artifact)
		}
		return artifact
	})
}

// Optimize reads the optimizer engine from options ("engine"/"optimizer") and
// delegates to OptimizeWith.
func (a *AxAgent) Optimize(dataset Value, options map[string]Value) (Value, error) {
	opts := options
	if opts == nil {
		opts = Object()
	}
	engine, ok := coreGet(opts, "engine", coreGet(opts, "optimizer", nil)).(OptimizerEngine)
	if !ok || engine == nil {
		return nil, AxError{Category: "validation", Message: "options.engine must implement OptimizerEngine for optimize()"}
	}
	return a.OptimizeWith(engine, dataset, opts)
}
func (g *AxGen) EvaluateOptimization(client AIClient, dataset Value, candidateMap map[string]Value, options map[string]Value) Value {
	opts := options
	if opts == nil {
		opts = Object()
	}
	normalized := asMap(mustCore(_normalize_optimization_dataset(dataset)))
	rows := MutableArray()
	original := asMap(mustCore(_optimization_component_current_map(g.GetOptimizableComponents())))
	candidate := cloneMap(candidateMap)
	phase := coreGet(opts, "phase", "train")
	defer g.ApplyOptimizedComponents(original)
	if coreTruthy(candidate) {
		g.ApplyOptimizedComponents(candidate)
	}
	for _, rawTask := range asSlice(coreGet(normalized, "train", Array())) {
		task, isMap := rawTask.(map[string]Value)
		if !isMap {
			task = Object()
		}
		var errVal Value
		var prediction Value
		input := rawTask
		if isMap {
			input = coreGet(task, "input", task)
		}
		output, err := g.Forward(context.Background(), client, asMap(input), asMap(coreGet(opts, "forward_options", Object())))
		if err == nil {
			prediction = Object("completionType", "final", "output", output, "finalOutput", output, "functionCalls", g.FunctionCallTraces, "actionLog", g.ChatLog, "usage", Object(), "trace", Object("traces", g.Traces))
		} else {
			errVal = Object("message", err.Error())
			prediction = Object("completionType", "error", "error", errVal, "functionCalls", g.FunctionCallTraces, "actionLog", g.ChatLog, "usage", Object(), "trace", Object("traces", g.Traces))
		}
		scores, scalar := scoreOptimizationPrediction(task, prediction, opts)
		rows = coreAppend(rows, mustCore(_build_optimization_eval_row(rawTask, prediction, scores, scalar, coreGet(prediction, "trace", nil), errVal))).(*AxArray)
	}
	return mustCore(_build_optimization_eval_result(rows, candidate, phase))
}

type AxFlow struct {
	State   map[string]Value
	Steps   Value
	Options map[string]Value
}

func NewFlow(options map[string]Value) *AxFlow {
	if options == nil {
		options = Object()
	}
	state := asMap(mustCore(_flow_factory(options)))
	return &AxFlow{State: state, Steps: coreGet(state, "steps", Array()), Options: options}
}
func (f *AxFlow) Execute(name string, program AxProgram, options map[string]Value) *AxFlow {
	if options == nil {
		options = Object()
	}
	step := mustCore(_flow_step("program", name, program, options))
	mustCore(_flow_add_step(f.State, step))
	f.Steps = coreGet(f.State, "steps", Array())
	return f
}
func (f *AxFlow) Returns(mapping map[string]Value) *AxFlow {
	mustCore(_flow_set_returns(f.State, mapping))
	return f
}
func (f *AxFlow) GetPlan() Value { return mustCore(_flow_plan(f.State)) }
func (f *AxFlow) Forward(ctx context.Context, client AIClient, values map[string]Value, options map[string]Value) (Value, error) {
	return safeValue(func() Value {
		return mustCore(_flow_forward(f.State, bindAIClientContext(ctx, client), values, options))
	})
}
func (f *AxFlow) GetOptimizableComponents() Value {
	return mustCore(_flow_get_optimizable_components(f.State))
}
func (f *AxFlow) ApplyOptimizedComponents(m map[string]Value) {
	mustCore(_flow_apply_optimized_components(f.State, m))
}
func (f *AxFlow) EvaluateOptimization(client AIClient, dataset Value, candidateMap map[string]Value, options map[string]Value) Value {
	if candidateMap == nil {
		candidateMap = Object()
	}
	if options == nil {
		options = Object()
	}
	return mustCore(_flow_evaluate_optimization(f.State, client, dataset, candidateMap, options))
}

type OptimizerEngine interface {
	Optimize(map[string]Value, OptimizerEvaluator) (Value, error)
}
type OptimizerEvaluator interface {
	Evaluate(map[string]Value, map[string]Value) (Value, error)
}
type AxBootstrapFewShot struct{ Options map[string]Value }

func NewBootstrapFewShot(options map[string]Value) *AxBootstrapFewShot {
	if options == nil {
		options = Object()
	}
	return &AxBootstrapFewShot{Options: options}
}
func (b *AxBootstrapFewShot) Optimize(request map[string]Value, evaluator OptimizerEvaluator) (Value, error) {
	return safeValue(func() Value {
		if evaluator == nil {
			panic(AxError{Category: "optimize", Message: "AxBootstrapFewShot requires an OptimizerEvaluator"})
		}
		options := cloneMap(b.Options)
		for key, value := range asMap(coreGet(request, "options", Object())) {
			if key != "__order" {
				coreSet(options, key, value)
			}
		}
		components := asSlice(coreGet(request, "components", Array()))
		dataset := asMap(coreGet(request, "dataset", Object()))
		train := asSlice(coreGet(dataset, "train", Array()))
		threshold := num(coreGet(options, "qualityThreshold", coreGet(options, "quality_threshold", 0.5)))
		maxRounds := int(num(coreGet(options, "maxRounds", coreGet(options, "max_rounds", 3))))
		maxExamples := int(num(coreGet(options, "maxExamples", coreGet(options, "max_examples", 16))))
		maxDemos := int(num(coreGet(options, "maxDemos", coreGet(options, "max_demos", 4))))
		batchSize := int(num(coreGet(options, "batchSize", coreGet(options, "batch_size", 1))))
		if maxRounds <= 0 {
			maxRounds = 1
		}
		if maxExamples <= 0 {
			maxExamples = 1
		}
		if maxDemos <= 0 {
			maxDemos = 1
		}
		if batchSize <= 0 {
			batchSize = 1
		}
		if maxExamples < len(train) {
			train = train[:maxExamples]
		}
		base := gepaCurrentMap(components)
		demos := Array()
		accepted := map[string]bool{}
		totalCalls := 0
		for round := 0; round < maxRounds && len(demos) < maxDemos; round++ {
			for offset := 0; offset < len(train) && len(demos) < maxDemos; offset += batchSize {
				end := offset + batchSize
				if end > len(train) {
					end = len(train)
				}
				for _, example := range train[offset:end] {
					if len(demos) >= maxDemos {
						break
					}
					exampleKey := stableStringify(example)
					if accepted[exampleKey] {
						continue
					}
					result, err := evaluator.Evaluate(cloneMap(base), Object("dataset", Object("train", Array(example), "validation", Array()), "phase", "bootstrap", "round", round))
					if err != nil {
						panic(err)
					}
					rows := asSlice(coreGet(result, "rows", Array()))
					totalCalls += int(num(coreGet(result, "count", len(rows))))
					if len(rows) == 0 {
						continue
					}
					row := asMap(rows[0])
					if num(coreGet(row, "scalar", 0)) >= threshold {
						accepted[exampleKey] = true
						demos = append(demos, Object("programId", "root", "traces", Array(cloneValue(coreGet(row, "prediction", coreGet(row, "input", Object()))))))
					}
				}
			}
		}
		return Object("artifactVersion", "axir-optimized-artifact-v1", "optimizerName", "BootstrapFewShot", "optimizerVersion", "axir-bootstrap-fewshot-v1", "componentMap", Object(), "demos", demos, "metadata", Object("optimizer", "BootstrapFewShot", "qualityThreshold", threshold, "totalMetricCalls", totalCalls, "demosGenerated", len(demos)), "evidence", Object("count", totalCalls), "provenance", Object("sourceProgramKind", coreGet(request, "programKind", "unknown")))
	})
}

func Optimize(program AxProgram, examples Value, options map[string]Value) (Value, error) {
	return safeValue(func() Value {
		if options == nil {
			options = Object()
		}
		student := optimizeOption(options, "studentAI", "student_ai", "student", "client", "ai")
		teacher := optimizeOption(options, "teacherAI", "teacher_ai", "teacher", "reflectionAI", "reflection_ai", "reflection_client")
		if teacher == nil {
			teacher = student
		}
		data := examples
		if data == nil {
			data = Array()
		}
		bootstrapSetting := coreGet(options, "bootstrap", len(asSlice(data)) <= 8)
		evaluator := &axOptimizeDatasetEvaluator{Dataset: data, Options: options}
		var demos Value = Array()
		if !isFalse(bootstrapSetting) {
			bootstrapOptions := cloneMap(options)
			for key, value := range asMap(bootstrapSetting) {
				if key != "__order" {
					coreSet(bootstrapOptions, key, value)
				}
			}
			coreSet(bootstrapOptions, "apply", false)
			bootstrap := NewBootstrapFewShot(bootstrapOptions)
			artifact := optimizeWithEngine(program, bootstrap, data, bootstrapOptions, evaluator)
			demos = coreGet(artifact, "demos", Array())
			applyProgramDemos(program, demos)
		}
		gepaOptions := cloneMap(options)
		coreSet(gepaOptions, "bootstrap", false)
		if coreGet(gepaOptions, "maxMetricCalls", nil) == nil && coreGet(gepaOptions, "max_metric_calls", nil) == nil {
			coreSet(gepaOptions, "maxMetricCalls", 100)
		}
		coreSet(gepaOptions, "apply", false)
		reflection, _ := teacher.(AIClient)
		gepa := NewGEPA(reflection, gepaOptions)
		artifact := optimizeWithEngine(program, gepa, data, gepaOptions, evaluator)
		artifactMap := asMap(artifact)
		if len(asSlice(demos)) > 0 {
			coreSet(artifactMap, "demos", demos)
		}
		return artifactMap
	})
}

func optimizeOption(options map[string]Value, keys ...string) Value {
	for _, key := range keys {
		if value := coreGet(options, key, nil); value != nil {
			return value
		}
	}
	return nil
}
func isFalse(value Value) bool { b, ok := value.(bool); return ok && !b }
func optimizeProgramKind(program AxProgram) string {
	switch program.(type) {
	case *AxGen:
		return "axgen"
	case *AxFlow:
		return "flow"
	case *AxAgent:
		return "agent"
	default:
		return "program"
	}
}
func optimizeWithEngine(program AxProgram, engine OptimizerEngine, examples Value, options map[string]Value, evaluator OptimizerEvaluator) Value {
	components := program.GetOptimizableComponents()
	run := asMap(mustCore(_prepare_optimizer_run(optimizeProgramKind(program), components, examples, options, Object(), true)))
	response, err := engine.Optimize(asMap(coreGet(run, "request", Object())), evaluator)
	if err != nil {
		panic(err)
	}
	artifact := mustCore(_normalize_optimizer_engine_response(response, coreGet(response, "optimizerName", "optimizer"), coreGet(response, "optimizerVersion", "host"), components))
	if rawApply := coreGet(options, "apply", nil); rawApply != nil && coreTruthy(rawApply) {
		program.ApplyOptimizedComponents(asMap(coreGet(artifact, "componentMap", Object())))
	}
	return artifact
}
func applyProgramDemos(program AxProgram, demos Value) {
	switch p := program.(type) {
	case *AxGen:
		p.Demos = demos
	case *AxFlow:
		coreSet(p.State, "demos", demos)
	}
}

type axOptimizeDatasetEvaluator struct {
	Dataset Value
	Options map[string]Value
}

func (e *axOptimizeDatasetEvaluator) Evaluate(candidateMap map[string]Value, options map[string]Value) (Value, error) {
	normalized := asMap(mustCore(_normalize_optimization_dataset(coreGet(options, "dataset", e.Dataset))))
	rows := Array()
	for _, rawTask := range asSlice(coreGet(normalized, "train", Array())) {
		task := asMap(rawTask)
		rawScore := coreGet(task, "metric_score", coreGet(task, "scores", coreGet(task, "score", 1)))
		scores := mustCore(_normalize_optimization_metric_scores(rawScore))
		scalar := mustCore(_scalarize_optimization_scores(scores, e.Options))
		prediction := Object("completionType", "final", "output", candidateMap, "finalOutput", candidateMap, "functionCalls", Array(), "actionLog", Array(), "usage", Object(), "trace", Object("candidateMap", candidateMap))
		rows = append(rows, mustCore(_build_optimization_eval_row(task, prediction, scores, scalar, coreGet(prediction, "trace", nil), nil)))
	}
	return mustCore(_build_optimization_eval_result(rows, candidateMap, coreGet(options, "phase", "train"))), nil
}

type AxGEPA struct {
	Options          map[string]Value
	ReflectionClient AIClient
}

func NewGEPA(reflectionClient AIClient, options map[string]Value) *AxGEPA {
	return &AxGEPA{Options: options, ReflectionClient: reflectionClient}
}
func (g *AxGEPA) Optimize(request map[string]Value, evaluator OptimizerEvaluator) (Value, error) {
	return safeValue(func() Value { return g.optimize(request, evaluator) })
}
func (g *AxGEPA) optimize(request map[string]Value, evaluator OptimizerEvaluator) Value {
	if evaluator == nil {
		panic(AxError{Category: "optimize", Message: "AxGEPA requires an OptimizerEvaluator"})
	}
	options := cloneMap(g.Options)
	for key, value := range asMap(coreGet(request, "options", Object())) {
		if key != "__order" {
			coreSet(options, key, value)
		}
	}
	components := Array()
	for _, raw := range asSlice(coreGet(request, "components", Array())) {
		component := asMap(raw)
		if _, ok := coreGet(component, "current", "").(string); ok {
			components = append(components, cloneMap(component))
		}
	}
	if len(components) == 0 {
		panic(AxError{Category: "optimize", Message: "AxGEPA: program exposes no optimizable components"})
	}
	dataset := asMap(coreGet(request, "dataset", Object()))
	train := asSlice(coreGet(dataset, "train", Array()))
	validation := asSlice(coreGet(dataset, "validation", Array()))
	if len(validation) == 0 {
		validation = train
	}
	maxCalls := int(num(coreGet(options, "maxMetricCalls", coreGet(options, "max_metric_calls", 0))))
	if maxCalls <= 0 {
		panic(AxError{Category: "optimize", Message: "AxGEPA: options.maxMetricCalls must be set to a positive integer"})
	}
	numTrials := int(num(coreGet(options, "numTrials", coreGet(options, "num_trials", 30))))
	if numTrials < 0 {
		numTrials = 0
	}
	minibatchSize := int(num(coreGet(options, "minibatchSize", coreGet(options, "minibatch_size", 20))))
	if minibatchSize <= 0 {
		minibatchSize = 1
	}
	paretoSize := int(num(coreGet(options, "paretoSetSize", coreGet(options, "pareto_set_size", minibatchSize*3))))
	if paretoSize <= 0 {
		paretoSize = 1
	}
	if paretoSize > len(validation) {
		paretoSize = len(validation)
	}
	paretoSet := validation
	if paretoSize < len(validation) {
		paretoSet = validation[:paretoSize]
	}
	baseCfg := gepaCurrentMap(components)
	selectorState := gepaSelectorState(components, asMap(coreGet(options, "selectorState", coreGet(options, "selector_state", Object()))))
	totalCalls := 0
	demos := Array()
	if bootstrap := coreGet(options, "bootstrap", nil); bootstrap != nil && !isFalse(bootstrap) {
		var nextCalls int
		demos, nextCalls = g.gepaBootstrap(evaluator, baseCfg, train, asMap(bootstrap), totalCalls, maxCalls)
		totalCalls = nextCalls
	}
	if maxCalls <= len(paretoSet) {
		panic(AxError{Category: "optimize", Message: fmt.Sprintf("AxGEPA: options.maxMetricCalls=%d is too small to evaluate the initial Pareto set; need at least %d metric calls", maxCalls, len(paretoSet))})
	}
	baseEval, nextCalls := gepaEvaluate(evaluator, baseCfg, paretoSet, "initial Pareto evaluation", maxCalls, totalCalls, true)
	totalCalls = nextCalls
	bestCfg := cloneMap(baseCfg)
	bestScore := num(coreGet(baseEval, "avg", 0))
	candidatesExplored := 1
	if numTrials > 0 {
		if g.ReflectionClient == nil {
			panic(AxError{Category: "optimize", Message: "AxGEPA requires a reflection_client for reflective trials"})
		}
		target := asMap(components[0])
		if len(components) > 1 {
			target = asMap(components[len(components)-1])
		}
		group := gepaComponentGroup(target, components)
		proposed := cloneMap(baseCfg)
		parentEval, ok := gepaEvaluateOptional(evaluator, bestCfg, gepaMinibatch(train, minibatchSize), "parent minibatch", maxCalls, totalCalls)
		if ok {
			totalCalls = int(num(coreGet(parentEval, "_totalCalls", totalCalls)))
			rows := asSlice(coreGet(parentEval, "rows", Array()))
			for _, rawComponent := range group {
				component := asMap(rawComponent)
				cid := display(coreGet(component, "id", ""))
				gepaRecordProposal(selectorState, cid)
				current := display(coreGet(proposed, cid, ""))
				next := g.gepaReflect(component, current, rows, options)
				coreSet(proposed, cid, next)
			}
			childEval, childOK := gepaEvaluateOptional(evaluator, proposed, gepaMinibatch(train, minibatchSize), "child minibatch", maxCalls, totalCalls)
			if childOK {
				totalCalls = int(num(coreGet(childEval, "_totalCalls", totalCalls)))
				accepted := num(coreGet(childEval, "sum", 0)) > num(coreGet(parentEval, "sum", 0))
				for _, rawComponent := range group {
					gepaRecordResult(selectorState, display(coreGet(rawComponent, "id", "")), accepted, 0)
				}
				if accepted {
					validationEval, validationOK := gepaEvaluateOptional(evaluator, proposed, paretoSet, "validation evaluation", maxCalls, totalCalls)
					if validationOK {
						totalCalls = int(num(coreGet(validationEval, "_totalCalls", totalCalls)))
						bestCfg = cloneMap(proposed)
						bestScore = num(coreGet(validationEval, "avg", coreGet(childEval, "avg", bestScore)))
						candidatesExplored = 2
					}
				}
			}
		}
	}
	owners := Object()
	for _, raw := range components {
		component := asMap(raw)
		id := display(coreGet(component, "id", ""))
		owner := coreGet(component, "owner", strings.SplitN(id, "::", 2)[0])
		coreSet(owners, id, owner)
	}
	metadata := Object("optimizer", "GEPA", "selectorState", selectorState, "bestScore", bestScore, "totalMetricCalls", totalCalls, "candidatesExplored", candidatesExplored, "report", Object("summary", "GEPA Multi-Objective Optimization Complete", "statistics", Object("totalEvaluations", totalCalls, "candidatesExplored", candidatesExplored, "converged", true), "paretoFrontier", Object("solutionCount", 1, "hypervolume", 0)))
	return Object("artifactVersion", "axir-optimized-artifact-v1", "optimizerName", "GEPA", "optimizerVersion", "axir-gepa-v1", "componentMap", bestCfg, "demos", demos, "metadata", metadata, "evidence", Object("avg", bestScore, "count", len(paretoSet), "totalMetricCalls", totalCalls), "provenance", Object("sourceProgramKind", coreGet(request, "programKind", "unknown"), "componentOwners", owners))
}

func gepaCurrentMap(components []Value) map[string]Value {
	out := Object()
	for _, raw := range components {
		component := asMap(raw)
		coreSet(out, coreGet(component, "id", ""), coreGet(component, "current", ""))
	}
	return out
}
func gepaSelectorState(components []Value, initial map[string]Value) map[string]Value {
	out := Object()
	for _, raw := range components {
		component := asMap(raw)
		id := display(coreGet(component, "id", ""))
		old := asMap(coreGet(initial, id, Object()))
		coreSet(out, id, Object("proposals", int(num(coreGet(old, "proposals", 0))), "accepts", int(num(coreGet(old, "accepts", 0))), "lastAcceptIter", int(num(coreGet(old, "lastAcceptIter", -1))), "stagnation", int(num(coreGet(old, "stagnation", 0)))))
	}
	return out
}
func gepaEvaluate(evaluator OptimizerEvaluator, cfg map[string]Value, examples []Value, phase string, maxCalls int, totalCalls int, throw bool) (map[string]Value, int) {
	needed := len(examples)
	if totalCalls+needed > maxCalls {
		if throw {
			panic(AxError{Category: "optimize", Message: fmt.Sprintf("AxGEPA: options.maxMetricCalls=%d is too small to evaluate the initial Pareto set; need at least %d metric calls", maxCalls, needed)})
		}
		return nil, totalCalls
	}
	result, err := evaluator.Evaluate(cloneMap(cfg), Object("dataset", Object("train", valuesToArray(examples), "validation", Array()), "phase", phase, "captureTraces", true))
	if err != nil {
		panic(err)
	}
	out := cloneMap(asMap(result))
	coreSet(out, "_totalCalls", totalCalls+int(num(coreGet(out, "count", needed))))
	return out, totalCalls + int(num(coreGet(out, "count", needed)))
}
func gepaEvaluateOptional(evaluator OptimizerEvaluator, cfg map[string]Value, examples []Value, phase string, maxCalls int, totalCalls int) (map[string]Value, bool) {
	result, next := gepaEvaluate(evaluator, cfg, examples, phase, maxCalls, totalCalls, false)
	if result == nil {
		return Object("_totalCalls", totalCalls), false
	}
	return result, next > totalCalls
}
func valuesToArray(values []Value) Value {
	out := Array()
	for _, value := range values {
		out = append(out, value)
	}
	return out
}
func (g *AxGEPA) gepaBootstrap(evaluator OptimizerEvaluator, cfg map[string]Value, train []Value, options map[string]Value, totalCalls int, maxCalls int) ([]Value, int) {
	threshold := num(coreGet(options, "scoreThreshold", coreGet(options, "score_threshold", 0.8)))
	maxDemos := int(num(coreGet(options, "maxBootstrapDemos", coreGet(options, "max_bootstrap_demos", 4))))
	maxBootCalls := int(num(coreGet(options, "maxBootstrapMetricCalls", coreGet(options, "max_bootstrap_metric_calls", len(train)))))
	if maxDemos <= 0 {
		maxDemos = 1
	}
	if maxBootCalls <= 0 {
		maxBootCalls = 1
	}
	demos := Array()
	calls := 0
	for _, example := range train {
		if calls >= maxBootCalls || len(demos) >= maxDemos {
			break
		}
		result, next := gepaEvaluate(evaluator, cfg, []Value{example}, "bootstrap", maxCalls, totalCalls, false)
		totalCalls = next
		calls++
		if result == nil {
			continue
		}
		rows := asSlice(coreGet(result, "rows", Array()))
		if len(rows) == 0 {
			continue
		}
		row := asMap(rows[0])
		if num(coreGet(row, "scalar", 0)) >= threshold {
			demos = append(demos, Object("programId", "root", "traces", Array(cloneValue(coreGet(row, "prediction", coreGet(row, "input", Object()))))))
		}
	}
	return demos, totalCalls
}
func gepaMinibatch(train []Value, size int) []Value {
	if size <= 0 || size >= len(train) {
		return train
	}
	return train[:size]
}
func gepaComponentGroup(component map[string]Value, components []Value) []Value {
	byID := map[string]map[string]Value{}
	for _, raw := range components {
		c := asMap(raw)
		byID[display(coreGet(c, "id", ""))] = c
	}
	out := []Value{}
	seen := map[string]bool{}
	var visit func(string)
	visit = func(id string) {
		if seen[id] {
			return
		}
		c, ok := byID[id]
		if !ok {
			return
		}
		seen[id] = true
		out = append(out, c)
		for _, dep := range asSlice(coreGet(c, "dependsOn", coreGet(c, "depends_on", Array()))) {
			visit(display(dep))
		}
	}
	visit(display(coreGet(component, "id", "")))
	return out
}
func (g *AxGEPA) gepaReflect(component map[string]Value, current string, rows []Value, options map[string]Value) string {
	attempts := int(num(coreGet(options, "maxReflectionAttempts", coreGet(options, "max_reflection_attempts", 2))))
	if attempts <= 0 {
		attempts = 1
	}
	for i := 0; i < attempts; i++ {
		response, err := g.ReflectionClient.Chat(context.Background(), Object("chatPrompt", Array(Object("role", "user", "content", stableStringify(Object("componentKey", coreGet(component, "id", ""), "currentValue", current, "rows", rows))))), Object())
		if err != nil {
			panic(err)
		}
		candidate := gepaExtractReflectionText(response)
		if gepaValidateComponent(component, candidate) {
			return candidate
		}
	}
	return current
}
func gepaExtractReflectionText(response Value) string {
	results := asSlice(coreGet(response, "results", Array()))
	text := ""
	if len(results) > 0 {
		text = display(coreGet(results[0], "content", ""))
	}
	text = strings.TrimSpace(text)
	text = strings.TrimSpace(strings.TrimPrefix(text, "New Value:"))
	return text
}
func gepaValidateComponent(component map[string]Value, candidate string) bool {
	if candidate == "" {
		return false
	}
	for _, raw := range asSlice(coreGet(component, "preserve", Array())) {
		if !strings.Contains(candidate, display(raw)) {
			return false
		}
	}
	if display(coreGet(component, "format", "")) == "snake_case" && strings.Contains(candidate, " ") {
		return false
	}
	return true
}
func gepaRecordProposal(selector map[string]Value, id string) {
	state := asMap(coreGet(selector, id, Object()))
	coreSet(state, "proposals", int(num(coreGet(state, "proposals", 0)))+1)
	coreSet(selector, id, state)
}
func gepaRecordResult(selector map[string]Value, id string, accepted bool, iteration int) {
	state := asMap(coreGet(selector, id, Object()))
	if accepted {
		coreSet(state, "accepts", int(num(coreGet(state, "accepts", 0)))+1)
		coreSet(state, "lastAcceptIter", iteration)
		coreSet(state, "stagnation", 0)
	} else {
		coreSet(state, "stagnation", int(num(coreGet(state, "stagnation", 0)))+1)
	}
	coreSet(selector, id, state)
}

// AxACE is the Agentic Context Engineering optimizer (Generator -> Reflector ->
// Curator). Deterministic playbook mutations reuse the Core-owned _ace_* ops;
// the LLM-orchestrated reflect/curate steps are delegated to injected callables
// so the loop is reproducible under conformance with scripted responses.
type ACEReflector func(payload map[string]Value) Value
type ACECurator func(payload map[string]Value) Value
type ACEGenerator func(example map[string]Value) map[string]Value

type AxACE struct {
	Reflector        ACEReflector
	Curator          ACECurator
	Generator        ACEGenerator
	Options          map[string]Value
	config           map[string]Value
	initialPlaybook  Value
	now              string
	playbook         Value
	generatorHistory []Value
	deltaHistory     []Value
	lastPrediction   Value
}

func NewACE(reflector ACEReflector, curator ACECurator, generator ACEGenerator, options map[string]Value) *AxACE {
	if options == nil {
		options = Object()
	}
	config := Object(
		"maxEpochs", 1,
		"maxReflectorRounds", 2,
		"maxSectionSize", 25,
		"maxSerializedFieldChars", 2000,
		"similarityThreshold", 0.95,
		"allowDynamicSections", true,
	)
	for _, key := range []string{"maxEpochs", "maxReflectorRounds", "maxSectionSize", "maxSerializedFieldChars", "similarityThreshold", "allowDynamicSections"} {
		if value := coreGet(options, key, nil); value != nil {
			coreSet(config, key, value)
		}
	}
	now := "1970-01-01T00:00:00.000Z"
	if value := coreGet(options, "now", nil); value != nil {
		now = display(value)
	}
	initialPlaybook := coreGet(options, "initialPlaybook", nil)
	var playbook Value
	if initialPlaybook != nil {
		playbook = cloneValue(initialPlaybook)
	} else {
		playbook = mustCore(_ace_empty_playbook(nil, now))
	}
	return &AxACE{
		Reflector:       reflector,
		Curator:         curator,
		Generator:       generator,
		Options:         options,
		config:          config,
		initialPlaybook: initialPlaybook,
		now:             now,
		playbook:        playbook,
	}
}

func (a *AxACE) Name() string    { return "ACE" }
func (a *AxACE) Version() string { return "axir-ace-v1" }

func (a *AxACE) intConfig(key string, fallback int) int {
	if value := coreGet(a.config, key, nil); value != nil {
		return int(num(value))
	}
	return fallback
}

func (a *AxACE) Reset() {
	if a.initialPlaybook != nil {
		a.playbook = cloneValue(a.initialPlaybook)
	} else {
		a.playbook = mustCore(_ace_empty_playbook(nil, a.now))
	}
	a.generatorHistory = nil
	a.deltaHistory = nil
}

func (a *AxACE) ConfigureAuto(level string) {
	switch level {
	case "light":
		coreSet(a.config, "maxEpochs", 1)
		coreSet(a.config, "maxReflectorRounds", 1)
	case "medium":
		coreSet(a.config, "maxEpochs", 2)
		coreSet(a.config, "maxReflectorRounds", 2)
	case "heavy":
		coreSet(a.config, "maxEpochs", 3)
		coreSet(a.config, "maxReflectorRounds", 3)
	}
}

func (a *AxACE) Hydrate(state map[string]Value) {
	if state == nil {
		state = Object()
	}
	if pb := coreGet(state, "playbook", nil); pb != nil {
		a.playbook = cloneValue(pb)
	} else if a.initialPlaybook != nil {
		a.playbook = cloneValue(a.initialPlaybook)
	} else {
		a.playbook = mustCore(_ace_empty_playbook(nil, a.now))
	}
	artifact := asMap(coreGet(state, "artifact", Object()))
	a.generatorHistory = asSlice(cloneValue(coreGet(artifact, "feedback", Array())))
	a.deltaHistory = asSlice(cloneValue(coreGet(artifact, "history", Array())))
}

func (a *AxACE) GetPlaybook() Value { return cloneValue(a.playbook) }

func (a *AxACE) GetArtifact() Value { return a.createArtifact() }

func (a *AxACE) createArtifact() Value {
	return Object(
		"playbook", cloneValue(a.playbook),
		"feedback", cloneValue(a.generatorHistory),
		"history", cloneValue(a.deltaHistory),
	)
}

func (a *AxACE) renderPlaybook() string {
	return display(mustCore(_ace_render_playbook(cloneValue(a.playbook))))
}

func (a *AxACE) generatorOutput(prediction Value) map[string]Value {
	reasoning := ""
	bulletIds := Array()
	if m, ok := prediction.(map[string]Value); ok {
		if thought := coreGet(m, "thought", nil); thought != nil {
			reasoning = display(thought)
		}
		if ids := coreGet(m, "bullet_ids", nil); ids != nil {
			if slice, ok := ids.([]Value); ok {
				bulletIds = append(Array(), slice...)
			}
		}
	}
	return Object("reasoning", reasoning, "answer", prediction, "bulletIds", bulletIds)
}

func (a *AxACE) runReflectionRounds(example map[string]Value, generatorOutput map[string]Value, feedback Value) Value {
	rounds := a.intConfig("maxReflectorRounds", 1)
	if rounds < 1 {
		rounds = 1
	}
	var previous Value
	for round := 0; round < rounds; round++ {
		reflection := a.runReflector(example, generatorOutput, feedback, previous)
		if reflection == nil || len(asMap(reflection)) == 0 {
			break
		}
		previous = reflection
		errorText := strings.TrimSpace(strings.ToLower(display(coreGet(reflection, "errorIdentification", ""))))
		resolved := false
		if metadata := coreGet(reflection, "metadata", nil); metadata != nil {
			if coreTruthy(coreGet(metadata, "resolved", false)) {
				resolved = true
			}
		}
		if resolved || errorText == "" || strings.HasPrefix(errorText, "no error") || strings.HasPrefix(errorText, "resolved") {
			break
		}
	}
	return previous
}

func (a *AxACE) runReflector(example map[string]Value, generatorOutput map[string]Value, feedback Value, previousReflection Value) Value {
	if a.Reflector == nil {
		return nil
	}
	payload := Object(
		"question", example,
		"generator_answer", coreGet(generatorOutput, "answer", nil),
		"generator_reasoning", coreGet(generatorOutput, "reasoning", nil),
		"playbook", a.renderPlaybook(),
		"feedback", feedback,
		"previous_reflection", previousReflection,
	)
	return a.Reflector(payload)
}

func (a *AxACE) runCurator(example map[string]Value, reflection Value) Value {
	if reflection == nil {
		return nil
	}
	if a.Curator == nil {
		return nil
	}
	payload := Object(
		"playbook", a.renderPlaybook(),
		"reflection", reflection,
		"question_context", example,
		"token_budget", 1024,
	)
	return a.Curator(payload)
}

func aceCollectProtectedIds(operations []Value) []Value {
	out := Array()
	for _, opRaw := range operations {
		op := asMap(opRaw)
		if display(coreGet(op, "type", "")) == "UPDATE" && coreGet(op, "bulletId", nil) != nil {
			out = append(out, coreGet(op, "bulletId", nil))
		}
	}
	return out
}

func aceMetricFeedback(score Value) Value {
	if _, ok := score.(float64); ok {
		return "Metric score: " + stableStringify(score)
	}
	if _, ok := score.(int); ok {
		return "Metric score: " + stableStringify(score)
	}
	return nil
}

func aceIsNumber(value Value) bool {
	switch value.(type) {
	case int, int64, float64:
		return true
	}
	return false
}

func (a *AxACE) processExample(example map[string]Value, score Value, source string, epoch int, index int) {
	generatorOutput := a.generatorOutput(a.lastPrediction)
	reflection := a.runReflectionRounds(example, generatorOutput, aceMetricFeedback(score))
	rawCurator := a.runCurator(example, reflection)
	var rawOperations Value
	if rawCurator != nil {
		rawOperations = coreGet(rawCurator, "operations", nil)
	}
	operations := mustCore(_ace_normalize_curator_operations(rawOperations))
	resolved := asSlice(mustCore(_ace_resolve_curator_operation_targets(operations, a.playbook, reflection, generatorOutput)))
	var curatorResult Value
	if rawCurator != nil || len(resolved) > 0 {
		curatorResult = cloneMap(asMap(rawCurator))
		coreSet(curatorResult, "operations", resolved)
	}
	appliedIds := Array()
	if len(resolved) > 0 {
		options := Object(
			"maxSectionSize", coreGet(a.config, "maxSectionSize", nil),
			"allowDynamicSections", coreGet(a.config, "allowDynamicSections", nil),
			"enableAutoPrune", true,
			"protectedBulletIds", aceCollectProtectedIds(resolved),
		)
		result := mustCore(_ace_apply_curator_operations(a.playbook, resolved, options, a.now))
		a.playbook = coreGet(result, "playbook", nil)
		appliedIds = asSlice(coreGet(result, "updatedBulletIds", Array()))
		autoRemoved := asSlice(coreGet(result, "autoRemoved", Array()))
		if len(autoRemoved) > 0 {
			resolved = append(append(Array(), resolved...), autoRemoved...)
			if curatorResult != nil {
				coreSet(curatorResult, "operations", resolved)
			}
		}
	}
	if reflection != nil {
		for _, tagRaw := range asSlice(coreGet(reflection, "bulletTags", Array())) {
			tag := asMap(tagRaw)
			a.playbook = mustCore(_ace_update_bullet_feedback(a.playbook, coreGet(tag, "id", nil), coreGet(tag, "tag", nil), a.now))
		}
	}
	if len(resolved) > 0 && len(appliedIds) > 0 {
		a.playbook = mustCore(_ace_dedupe_playbook(a.playbook))
	}
	scoreValue := Value(0)
	if aceIsNumber(score) {
		scoreValue = score
	}
	feedbackEvent := Object(
		"example", example,
		"prediction", a.lastPrediction,
		"score", scoreValue,
		"generatorOutput", generatorOutput,
		"reflection", reflection,
		"curator", curatorResult,
		"timestamp", a.now,
	)
	a.generatorHistory = append(a.generatorHistory, feedbackEvent)
	if len(appliedIds) > 0 && curatorResult != nil && len(asSlice(coreGet(curatorResult, "operations", Array()))) > 0 {
		a.deltaHistory = append(a.deltaHistory, Object(
			"source", source,
			"epoch", epoch,
			"exampleIndex", index,
			"operations", coreGet(curatorResult, "operations", Array()),
		))
	}
}

func (a *AxACE) Compile(examples []Value, metricFn func(map[string]Value) Value, options map[string]Value) map[string]Value {
	if options == nil {
		options = Object()
	}
	aceOptions := coreGet(options, "aceOptions", nil)
	if aceOptions == nil {
		aceOptions = coreGet(options, "ace_options", nil)
	}
	if aceOptions != nil {
		for _, key := range []string{"maxEpochs", "maxReflectorRounds", "maxSectionSize", "maxSerializedFieldChars", "similarityThreshold", "allowDynamicSections"} {
			if value := coreGet(aceOptions, key, nil); value != nil {
				coreSet(a.config, key, value)
			}
		}
	}
	a.Reset()
	epochs := a.intConfig("maxEpochs", 1)
	if epochs < 1 {
		epochs = 1
	}
	var bestScore Value
	for epoch := 0; epoch < epochs; epoch++ {
		for index, exampleRaw := range examples {
			example := asMap(exampleRaw)
			var prediction Value
			if a.Generator != nil {
				prediction = a.Generator(example)
			} else {
				prediction = Object()
			}
			a.lastPrediction = prediction
			var score Value = 0
			if metricFn != nil {
				score = metricFn(example)
			}
			if aceIsNumber(score) {
				if bestScore == nil || num(score) > num(bestScore) {
					bestScore = score
				}
			}
			a.processExample(example, score, "compile", epoch, index)
		}
	}
	if bestScore == nil {
		bestScore = 0
	}
	return Object(
		"playbook", cloneValue(a.playbook),
		"artifact", a.createArtifact(),
		"bestScore", bestScore,
		"finalConfiguration", Object("strategy", "ace", "epochs", epochs),
	)
}

func (a *AxACE) ApplyOnlineUpdate(args map[string]Value) Value {
	if args == nil {
		args = Object()
	}
	if a.Generator == nil {
		panic(AxError{Category: "optimize", Message: "AxACE: compile must run before ApplyOnlineUpdate"})
	}
	example := asMap(coreGet(args, "example", Object()))
	prediction := coreGet(args, "prediction", nil)
	a.lastPrediction = prediction
	generatorOutput := a.generatorOutput(prediction)
	reflection := a.runReflectionRounds(example, generatorOutput, coreGet(args, "feedback", nil))
	rawCurator := a.runCurator(example, reflection)
	var rawOperations Value
	if rawCurator != nil {
		rawOperations = coreGet(rawCurator, "operations", nil)
	}
	operations := mustCore(_ace_normalize_curator_operations(rawOperations))
	resolved := asSlice(mustCore(_ace_resolve_curator_operation_targets(operations, a.playbook, reflection, generatorOutput)))
	var curatorResult Value
	if rawCurator != nil || len(resolved) > 0 {
		curatorResult = cloneMap(asMap(rawCurator))
		coreSet(curatorResult, "operations", resolved)
	}
	if reflection != nil {
		for _, tagRaw := range asSlice(coreGet(reflection, "bulletTags", Array())) {
			tag := asMap(tagRaw)
			a.playbook = mustCore(_ace_update_bullet_feedback(a.playbook, coreGet(tag, "id", nil), coreGet(tag, "tag", nil), a.now))
		}
	}
	appliedIds := Array()
	if len(resolved) > 0 {
		options := Object(
			"maxSectionSize", coreGet(a.config, "maxSectionSize", nil),
			"allowDynamicSections", coreGet(a.config, "allowDynamicSections", nil),
			"enableAutoPrune", true,
			"protectedBulletIds", aceCollectProtectedIds(resolved),
		)
		result := mustCore(_ace_apply_curator_operations(a.playbook, resolved, options, a.now))
		a.playbook = coreGet(result, "playbook", nil)
		appliedIds = asSlice(coreGet(result, "updatedBulletIds", Array()))
		autoRemoved := asSlice(coreGet(result, "autoRemoved", Array()))
		if len(autoRemoved) > 0 {
			resolved = append(append(Array(), resolved...), autoRemoved...)
			if curatorResult != nil {
				coreSet(curatorResult, "operations", resolved)
			}
		}
		a.playbook = mustCore(_ace_dedupe_playbook(a.playbook))
	}
	feedbackEvent := Object(
		"example", example,
		"prediction", prediction,
		"score", 0,
		"generatorOutput", generatorOutput,
		"reflection", reflection,
		"curator", curatorResult,
		"timestamp", a.now,
	)
	a.generatorHistory = append(a.generatorHistory, feedbackEvent)
	if len(appliedIds) > 0 && curatorResult != nil && len(asSlice(coreGet(curatorResult, "operations", Array()))) > 0 {
		a.deltaHistory = append(a.deltaHistory, Object(
			"source", "online",
			"epoch", -1,
			"exampleIndex", len(a.generatorHistory)-1,
			"operations", coreGet(curatorResult, "operations", Array()),
		))
	}
	return curatorResult
}

const aceReflectorSignature = "question:string \"Original task input serialized as JSON\", generator_answer:string \"Generator output serialized as JSON\", generator_reasoning?:string \"Generator reasoning trace\", playbook:string \"Current context playbook rendered as markdown\", expected_answer?:string \"Expected output when ground truth is available\", feedback?:string \"External feedback or reward signal\", previous_reflection?:string \"Most recent reflection JSON when running multi-round refinement\" -> reasoning:string \"Step-by-step analysis of generator performance\", errorIdentification:string \"Specific mistakes detected\", rootCauseAnalysis:string \"Underlying cause of the error\", correctApproach:string \"What the generator should do differently\", keyInsight:string \"Reusable insight to remember\", bulletTags:json \"Array of {id, tag} entries referencing playbook bullets\""

const aceCuratorSignature = "playbook:string \"Current playbook serialized as JSON\", reflection:string \"Latest reflection output serialized as JSON\", question_context:string \"Original task input serialized as JSON\", token_budget?:number \"Approximate token budget for curator response\" -> reasoning:string \"Justification for the proposed updates\", operations:json \"List of operations with type/section/content fields\""

func playbookComposeInstruction(base string, rendered string) string {
	parts := []string{}
	if trimmed := strings.TrimSpace(base); trimmed != "" {
		parts = append(parts, trimmed)
	}
	if trimmed := strings.TrimSpace(rendered); trimmed != "" {
		parts = append(parts, trimmed)
	}
	return strings.Join(parts, "\n\n")
}

func playbookStringify(value Value) string {
	if value == nil {
		return ""
	}
	if s, ok := value.(string); ok {
		return s
	}
	return stableStringify(value)
}

// AxPlaybook is a live, evolving context playbook bound to a program. It mirrors
// the TypeScript AxPlaybook: grow it offline from examples (Evolve), keep it
// growing online from live feedback (Update), render it into the program context
// (ApplyTo), and persist/restore it (ToJSON/Load). The evolution engine (ACE) is
// an implementation detail of this surface, just as Optimize hides GEPA.
type AxPlaybook struct {
	program          *AxGen
	engine           *AxACE
	studentAI        AIClient
	teacherAI        AIClient
	baseInstruction  string
	verbose          bool
	started          bool
	ctx              context.Context
	lastPrediction   Value
	reflectorProgram *AxGen
	curatorProgram   *AxGen
	applyHook        func(string)
}

func playbookOption(options map[string]Value, keys ...string) Value {
	for _, key := range keys {
		if value := coreGet(options, key, nil); value != nil {
			return value
		}
	}
	return nil
}

func playbookClient(value Value) AIClient {
	if value == nil {
		return nil
	}
	client, _ := value.(AIClient)
	return client
}

// Playbook builds an evolving context AxPlaybook for a program. Pass the student
// model under "studentAI" (and optionally "teacherAI"); the bound program is run
// with the student while reflection/curation use the teacher.
func Playbook(program *AxGen, options map[string]Value) *AxPlaybook {
	if options == nil {
		options = Object()
	}
	student := playbookClient(playbookOption(options, "studentAI", "student_ai", "student", "client", "ai"))
	if student == nil {
		panic(AxError{Category: "optimize", Message: "Playbook() requires studentAI or client"})
	}
	teacher := playbookClient(playbookOption(options, "teacherAI", "teacher_ai", "teacher"))
	if teacher == nil {
		teacher = student
	}
	engineOptions := Object()
	if value := coreGet(options, "now", nil); value != nil {
		coreSet(engineOptions, "now", value)
	}
	for _, pair := range [][]string{
		{"maxEpochs", "maxEpochs", "max_epochs"},
		{"maxReflectorRounds", "maxReflectorRounds", "max_reflector_rounds"},
		{"maxSectionSize", "maxSectionSize", "max_section_size"},
		{"allowDynamicSections", "allowDynamicSections", "allow_dynamic_sections"},
		{"initialPlaybook", "initialPlaybook", "initial_playbook"},
	} {
		if value := playbookOption(options, pair[1:]...); value != nil {
			coreSet(engineOptions, pair[0], value)
		}
	}
	pb := &AxPlaybook{
		program:   program,
		studentAI: student,
		teacherAI: teacher,
		verbose:   coreTruthy(coreGet(options, "verbose", false)),
		ctx:       context.Background(),
	}
	pb.engine = NewACE(pb.runReflector, pb.runCurator, pb.runGenerator, engineOptions)
	if auto := coreGet(options, "auto", nil); auto != nil {
		pb.engine.ConfigureAuto(display(auto))
	}
	if program != nil {
		pb.baseInstruction = program.Signature.Description
	}
	return pb
}

// The real LLM generator: run the bound program with the student client.
func (p *AxPlaybook) runGenerator(example map[string]Value) map[string]Value {
	if p.program == nil {
		return Object()
	}
	p.inject()
	out, err := p.program.Forward(p.ctx, p.studentAI, example, nil)
	if err != nil {
		panic(err)
	}
	prediction := asMap(out)
	p.lastPrediction = prediction
	return prediction
}

func (p *AxPlaybook) reflector() *AxGen {
	if p.reflectorProgram == nil {
		p.reflectorProgram = NewAx(aceReflectorSignature, Object("validation_retries", 1, "id", "ace.reflector"))
	}
	return p.reflectorProgram
}

func (p *AxPlaybook) curator() *AxGen {
	if p.curatorProgram == nil {
		p.curatorProgram = NewAx(aceCuratorSignature, Object("validation_retries", 1, "id", "ace.curator"))
	}
	return p.curatorProgram
}

// The real LLM reflector: a focused AxGen sub-program driven by the teacher.
func (p *AxPlaybook) runReflector(payload map[string]Value) Value {
	reflectorAI := p.teacherAI
	if reflectorAI == nil {
		reflectorAI = p.studentAI
	}
	request := Object(
		"question", playbookStringify(coreGet(payload, "question", nil)),
		"generator_answer", playbookStringify(coreGet(payload, "generator_answer", nil)),
		"playbook", coreGet(payload, "playbook", ""),
	)
	if reasoning := coreGet(payload, "generator_reasoning", nil); reasoning != nil {
		coreSet(request, "generator_reasoning", reasoning)
	}
	if feedback := coreGet(payload, "feedback", nil); feedback != nil {
		coreSet(request, "feedback", feedback)
	}
	if previous := coreGet(payload, "previous_reflection", nil); previous != nil {
		coreSet(request, "previous_reflection", playbookStringify(previous))
	}
	out, err := p.reflector().Forward(p.ctx, reflectorAI, request, nil)
	if err != nil {
		if p.verbose {
			fmt.Println("[AxPlaybook] reflector error:", err)
		}
		return nil
	}
	return out
}

// The real LLM curator: a focused AxGen sub-program driven by the teacher.
func (p *AxPlaybook) runCurator(payload map[string]Value) Value {
	curatorAI := p.teacherAI
	if curatorAI == nil {
		curatorAI = p.studentAI
	}
	request := Object(
		"playbook", coreGet(payload, "playbook", ""),
		"reflection", playbookStringify(coreGet(payload, "reflection", nil)),
		"question_context", playbookStringify(coreGet(payload, "question_context", nil)),
		"token_budget", coreGet(payload, "token_budget", 1024),
	)
	out, err := p.curator().Forward(p.ctx, curatorAI, request, nil)
	if err != nil {
		if p.verbose {
			fmt.Println("[AxPlaybook] curator error:", err)
		}
		return nil
	}
	return out
}

// Evolve grows the playbook offline from labeled examples, scoring each rollout
// with metricFn ({"prediction", "example"}), then renders the result into the
// bound program.
func (p *AxPlaybook) Evolve(ctx context.Context, examples []Value, metricFn func(map[string]Value) Value, options map[string]Value) (Value, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	p.ctx = ctx
	if options == nil {
		options = Object()
	}
	if auto := coreGet(options, "auto", nil); auto != nil {
		p.engine.ConfigureAuto(display(auto))
	}
	aceOptions := Object()
	if value := playbookOption(options, "maxEpochs", "max_epochs"); value != nil {
		coreSet(aceOptions, "maxEpochs", value)
	}
	wrappedMetric := func(example map[string]Value) Value {
		if metricFn == nil {
			return 0
		}
		return metricFn(Object("prediction", p.lastPrediction, "example", example))
	}
	return safeValue(func() Value {
		result := p.engine.Compile(examples, wrappedMetric, Object("aceOptions", aceOptions))
		p.started = true
		p.inject()
		return Object("bestScore", coreGet(result, "bestScore", 0), "playbook", coreGet(result, "playbook", nil))
	})
}

// Update refines the playbook online from a single live interaction. Safe to call
// without a prior Evolve/Load; the bound program is hydrated lazily on first use.
func (p *AxPlaybook) Update(ctx context.Context, args map[string]Value) (Value, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	p.ctx = ctx
	return safeValue(func() Value {
		if !p.started {
			p.engine.Hydrate(Object("playbook", p.engine.GetPlaybook()))
			p.started = true
		}
		result := p.engine.ApplyOnlineUpdate(args)
		p.inject()
		return result
	})
}

// ApplyTo renders the current playbook into a program context (defaults to the
// bound program).
func (p *AxPlaybook) ApplyTo(program *AxGen) {
	if program != nil && program != p.program {
		program.Signature.Description = playbookComposeInstruction(program.Signature.Description, p.Render())
		return
	}
	p.inject()
}

// Render returns the current playbook as a markdown block.
func (p *AxPlaybook) Render() string {
	return display(mustCore(_ace_render_playbook(p.engine.GetPlaybook())))
}

// GetState returns a serializable snapshot of the playbook and its history.
func (p *AxPlaybook) GetState() Value {
	return Object("playbook", p.engine.GetPlaybook(), "artifact", p.engine.GetArtifact())
}

// ToJSON aliases GetState.
func (p *AxPlaybook) ToJSON() Value { return p.GetState() }

// Load restores a snapshot into this handle and renders it into the bound program.
func (p *AxPlaybook) Load(snapshot map[string]Value) *AxPlaybook {
	if snapshot == nil {
		snapshot = Object()
	}
	p.engine.Hydrate(Object("playbook", coreGet(snapshot, "playbook", nil), "artifact", coreGet(snapshot, "artifact", nil)))
	p.started = true
	p.inject()
	return p
}

// ConfigureAuto sets the evolution intensity preset.
func (p *AxPlaybook) ConfigureAuto(level string) { p.engine.ConfigureAuto(level) }

// Reset clears the playbook back to its initial state.
func (p *AxPlaybook) Reset() {
	p.engine.Reset()
	p.started = false
}

// SetApplyHook redirects playbook injection. Used by AxAgent.Playbook to push the
// rendered playbook into a pipeline stage instead of the bare program.
func (p *AxPlaybook) SetApplyHook(hook func(string)) { p.applyHook = hook }

func (p *AxPlaybook) inject() {
	rendered := p.Render()
	if p.applyHook != nil {
		p.applyHook(rendered)
		return
	}
	if p.program != nil {
		base := p.baseInstruction
		if base == "" {
			base = p.program.Signature.Description
		}
		p.program.Signature.Description = playbookComposeInstruction(base, rendered)
	}
}

type CodeRuntime interface {
	Language() string
	UsageInstructions() string
	CreateSession(map[string]Value, map[string]Value) (CodeSession, error)
}
type CodeSession interface {
	Execute(string, map[string]Value) Value
	Inspect(map[string]Value) Value
	SnapshotGlobals(map[string]Value) Value
	PatchGlobals(Value, map[string]Value) Value
	Close() Value
}
type RuntimeCapabilities = map[string]Value
type RuntimeEnvelope = map[string]Value

type ProcessCodeRuntime struct {
	Command []string
	Env     map[string]string
	Cwd     string
	cmd     *exec.Cmd
	stdin   io.WriteCloser
	stdout  *bufio.Scanner
	stderr  bytes.Buffer
	nextID  int
	mu      sync.Mutex
}
type ProcessCodeSession struct {
	Runtime *ProcessCodeRuntime
	ID      string
}

func NewProcessCodeRuntime(command []string, env map[string]string) *ProcessCodeRuntime {
	return &ProcessCodeRuntime{Command: command, Env: env}
}
func NewProcessCodeRuntimeWithCwd(command []string, cwd string, env map[string]string) *ProcessCodeRuntime {
	return &ProcessCodeRuntime{Command: command, Cwd: cwd, Env: env}
}
func (r *ProcessCodeRuntime) Language() string { return "JavaScript" }
func (r *ProcessCodeRuntime) UsageInstructions() string {
	response, err := r.Request("capabilities", "", Object(), true)
	if err != nil {
		return ""
	}
	return display(coreGet(coreGet(response, "result", Object()), "usage_instructions", ""))
}
func (r *ProcessCodeRuntime) CreateSession(globals map[string]Value, options map[string]Value) (CodeSession, error) {
	response, err := r.Request("create_session", "", Object("globals", globals, "options", options), true)
	if err != nil {
		return nil, err
	}
	sessionID := display(coreGet(response, "session_id", coreGet(coreGet(response, "result", Object()), "session_id", "")))
	if sessionID == "" {
		return nil, AxError{Category: "runtime", Message: "runtime protocol did not return a session_id"}
	}
	return &ProcessCodeSession{Runtime: r, ID: sessionID}, nil
}
func (r *ProcessCodeRuntime) startLocked() error {
	if r.cmd != nil {
		return nil
	}
	if len(r.Command) == 0 {
		return AxError{Category: "runtime", Message: "ProcessCodeRuntime requires a command"}
	}
	cmd := exec.Command(r.Command[0], r.Command[1:]...)
	if r.Cwd != "" {
		cmd.Dir = r.Cwd
	}
	if r.Env != nil {
		env := os.Environ()
		for key, value := range r.Env {
			env = append(env, key+"="+value)
		}
		cmd.Env = env
	}
	stdin, err := cmd.StdinPipe()
	if err != nil {
		return err
	}
	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		return err
	}
	cmd.Stderr = &r.stderr
	if err := cmd.Start(); err != nil {
		return AxError{Category: "runtime", Message: "failed to start runtime protocol process: " + err.Error()}
	}
	scanner := bufio.NewScanner(stdoutPipe)
	scanner.Buffer(make([]byte, 1024), 16*1024*1024)
	r.cmd = cmd
	r.stdin = stdin
	r.stdout = scanner
	return nil
}
func (r *ProcessCodeRuntime) closedWithoutResponseMessageLocked() string {
	message := "runtime protocol process closed without a response"
	if r.cmd != nil {
		if r.cmd.ProcessState == nil {
			done := make(chan error, 1)
			go func() { done <- r.cmd.Wait() }()
			select {
			case err := <-done:
				if err != nil {
					if r.cmd.ProcessState != nil {
						message += " (exit code " + strconv.Itoa(r.cmd.ProcessState.ExitCode()) + ")"
					} else {
						message += ": " + err.Error()
					}
				}
			case <-time.After(100 * time.Millisecond):
			}
		} else if !r.cmd.ProcessState.Success() {
			message += ": exit code " + strconv.Itoa(r.cmd.ProcessState.ExitCode())
		}
		stderr := strings.TrimSpace(r.stderr.String())
		if stderr != "" {
			message += ": " + stderr
		}
	}
	return message
}
func (r *ProcessCodeRuntime) Request(op string, sessionID string, payload map[string]Value, throwOnError bool) (map[string]Value, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	if err := r.startLocked(); err != nil {
		return nil, err
	}
	r.nextID++
	id := strconv.Itoa(r.nextID)
	message := Object("id", id, "op", op, "payload", payload)
	if sessionID != "" {
		coreSet(message, "session_id", sessionID)
	}
	data, err := json.Marshal(runtimeJSONValue(message))
	if err != nil {
		return nil, AxError{Category: "protocol", Message: "runtime protocol request is not JSON-compatible: " + err.Error()}
	}
	if _, err := r.stdin.Write(append(data, '\n')); err != nil {
		return nil, AxError{Category: "protocol", Message: "runtime protocol write failed: " + err.Error()}
	}
	if !r.stdout.Scan() {
		if err := r.stdout.Err(); err != nil {
			return nil, AxError{Category: "protocol", Message: "runtime protocol read failed: " + err.Error()}
		}
		return nil, AxError{Category: "protocol", Message: r.closedWithoutResponseMessageLocked()}
	}
	line := r.stdout.Text()
	var parsed any
	if err := json.Unmarshal([]byte(line), &parsed); err != nil {
		return nil, AxError{Category: "protocol", Message: "runtime protocol invalid JSON response: " + err.Error()}
	}
	response := asMap(normalizeJSON(parsed))
	if len(response) == 0 {
		return nil, AxError{Category: "protocol", Message: "runtime protocol response must be an object"}
	}
	if display(coreGet(response, "id", "")) != id {
		return nil, AxError{Category: "protocol", Message: "runtime protocol response id mismatch"}
	}
	responseSessionID := display(coreGet(response, "session_id", ""))
	if sessionID != "" && responseSessionID != "" && responseSessionID != sessionID {
		return nil, AxError{Category: "protocol", Message: "runtime protocol session_id mismatch"}
	}
	if coreGet(response, "ok", true) == false && throwOnError {
		errObj := asMap(coreGet(response, "error", Object()))
		return nil, AxError{Category: display(coreGet(errObj, "category", "runtime")), Message: display(coreGet(errObj, "message", "runtime protocol error"))}
	}
	return response, nil
}
func (r *ProcessCodeRuntime) Close() Value {
	_, _ = r.Request("shutdown", "", Object(), false)
	r.mu.Lock()
	defer r.mu.Unlock()
	if r.cmd != nil && r.cmd.Process != nil {
		_ = r.cmd.Process.Kill()
		_ = r.cmd.Wait()
	}
	return Object("shutdown", true)
}
func runtimeEnvelopeError(message string, category string) Value {
	if category == "" {
		category = "runtime"
	}
	return Object("kind", "error", "error", message, "error_category", category, "is_error", true)
}
func (s *ProcessCodeSession) Execute(code string, options map[string]Value) Value {
	response, err := s.Runtime.Request("execute", s.ID, Object("code", code, "options", options), false)
	if err != nil {
		return runtimeEnvelopeError(err.Error(), "runtime")
	}
	if coreGet(response, "ok", true) == false {
		errObj := asMap(coreGet(response, "error", Object()))
		return runtimeEnvelopeError(display(coreGet(errObj, "message", "runtime protocol error")), display(coreGet(errObj, "category", "runtime")))
	}
	return coreGet(response, "result", Object())
}
func (s *ProcessCodeSession) Inspect(options map[string]Value) Value {
	response, err := s.Runtime.Request("inspect_globals", s.ID, options, true)
	if err != nil {
		panic(err)
	}
	return coreGet(response, "result", Object())
}
func (s *ProcessCodeSession) SnapshotGlobals(options map[string]Value) Value {
	response, err := s.Runtime.Request("snapshot_globals", s.ID, options, true)
	if err != nil {
		panic(err)
	}
	return coreGet(response, "result", Object())
}
func (s *ProcessCodeSession) PatchGlobals(snapshot Value, options map[string]Value) Value {
	response, err := s.Runtime.Request("patch_globals", s.ID, Object("globals", snapshot, "options", options), true)
	if err != nil {
		panic(err)
	}
	return coreGet(response, "result", Object())
}
func (s *ProcessCodeSession) Close() Value {
	response, err := s.Runtime.Request("close", s.ID, Object(), false)
	if err != nil {
		return Object("closed", true)
	}
	return coreGet(response, "result", Object("closed", true))
}

type conformanceScriptedCodeRuntime struct {
	Script         []Value
	Sessions       []*conformanceScriptedCodeSession
	CreateRequests []Value
	ExecuteOptions []Value
	Executed       []Value
	Capabilities   map[string]Value
	LanguageName   string
	Usage          string
}
type conformanceScriptedCodeSession struct {
	Runtime *conformanceScriptedCodeRuntime
	Globals map[string]Value
	Closed  bool
}

func newConformanceScriptedCodeRuntime(script Value, capabilities map[string]Value) *conformanceScriptedCodeRuntime {
	return &conformanceScriptedCodeRuntime{Script: append([]Value(nil), asSlice(script)...), Capabilities: capabilities, LanguageName: "JavaScript"}
}
func (r *conformanceScriptedCodeRuntime) Language() string {
	if r.LanguageName == "" {
		return "JavaScript"
	}
	return r.LanguageName
}
func (r *conformanceScriptedCodeRuntime) UsageInstructions() string { return r.Usage }
func (r *conformanceScriptedCodeRuntime) CreateSession(globals map[string]Value, options map[string]Value) (CodeSession, error) {
	session := &conformanceScriptedCodeSession{Runtime: r, Globals: cloneMap(globals)}
	r.Sessions = append(r.Sessions, session)
	r.CreateRequests = append(r.CreateRequests, Object("globals", cloneMap(globals), "options", cloneMap(options)))
	return session, nil
}
func (s *conformanceScriptedCodeSession) Execute(code string, options map[string]Value) Value {
	r := s.Runtime
	r.Executed = append(r.Executed, code)
	r.ExecuteOptions = append(r.ExecuteOptions, cloneMap(options))
	if s.Closed {
		return Object("kind", "session_closed", "message", "session closed")
	}
	if len(r.Script) == 0 {
		return Object("kind", "error", "error", Object("category", "runtime", "message", "runtime script exhausted"))
	}
	step := asMap(r.Script[0])
	r.Script = r.Script[1:]
	if expected := display(coreGet(step, "expected_code", "")); expected != "" && expected != code {
		return Object("kind", "error", "error", Object("category", "runtime", "message", "expected code "+expected+", got "+code))
	}
	for key, value := range asMap(coreGet(step, "bindings_patch", Object())) {
		if key != "__order" {
			coreSet(s.Globals, key, cloneValue(value))
		}
	}
	return cloneValue(coreGet(step, "result", Object("kind", "status", "status", Object("type", "success", "message", ""))))
}
func (s *conformanceScriptedCodeSession) Inspect(options map[string]Value) Value {
	if coreGet(s.Runtime.Capabilities, "inspect", true) == false {
		return Object("unavailable", "runtime state inspection unavailable")
	}
	return Object("globals", cloneMap(s.Globals), "closed", s.Closed)
}
func (s *conformanceScriptedCodeSession) SnapshotGlobals(options map[string]Value) Value {
	if coreGet(s.Runtime.Capabilities, "snapshot", true) == false {
		panic(AxError{Category: "runtime", Message: "AxCodeSession.snapshotGlobals() is required to export AxAgent state"})
	}
	return Object("closed", s.Closed, "globals", conformanceSanitizeRuntimeGlobals(s.Globals))
}
func (s *conformanceScriptedCodeSession) PatchGlobals(snapshot Value, options map[string]Value) Value {
	if coreGet(s.Runtime.Capabilities, "patch", true) == false {
		panic(AxError{Category: "runtime", Message: "AxCodeSession.patchGlobals() is required to restore AxAgent state"})
	}
	snap := asMap(snapshot)
	globals := coreGet(snap, "globals", snap)
	if !coreTruthy(coreTypeIs(globals, "object")) {
		return Object("kind", "error", "error", Object("category", "runtime", "message", "runtime session snapshot globals must be an object"))
	}
	for key, value := range asMap(globals) {
		if key != "__order" {
			coreSet(s.Globals, key, cloneValue(value))
		}
	}
	return Object("ok", true, "globals", conformanceSanitizeRuntimeGlobals(s.Globals))
}
func (s *conformanceScriptedCodeSession) Close() Value {
	s.Closed = true
	return Object("kind", "session_closed", "closed", true)
}
func conformanceSanitizeRuntimeGlobals(globals map[string]Value) map[string]Value {
	out := Object()
	reserved := map[string]bool{}
	for _, raw := range asSlice(mustCore(_agent_reserved_runtime_names())) {
		reserved[display(raw)] = true
	}
	for key, value := range globals {
		if key != "__order" && !reserved[key] {
			coreSet(out, key, cloneValue(value))
		}
	}
	return out
}

func objectCallMethod(target Value, method string, arg Value) (Value, error) {
	if method == "render" {
		return render_prompt(coreGet(target, "signature", nil), arg, coreGet(target, "functions", Array()), coreGet(target, "options", Object()))
	}
	if method == "call" {
		if fn, ok := target.(func(map[string]Value) Value); ok {
			return fn(asMap(arg)), nil
		}
	}
	return nil, AxError{Category: "runtime", Message: "unsupported method call: " + method}
}

// Host-boundary intrinsics used by generated Core.
func _core_axgen_render_examples(gen Value) Value {
	return _core_axgen_render_examples_impl(coreGet(gen, "examples", Array()), "Example", gen)
}
func _core_axgen_render_demos(gen Value) Value {
	return _core_axgen_render_examples_impl(coreGet(gen, "demos", Array()), "Demo", gen)
}
func _core_axgen_render_examples_impl(turns Value, label string, gen Value) Value {
	messages := Array()
	for _, raw := range coreIter(turns) {
		item := asMap(raw)
		input := coreGet(item, "input", Object())
		output := coreGet(item, "output", Object())
		messages = append(messages, Object("role", "user", "content", label+" Input:\n"+axgenFormatValues(gen, input)))
		messages = append(messages, Object("role", "assistant", "content", label+" Output:\n"+axgenFormatValues(gen, output)))
	}
	return messages
}
func axgenFormatValues(gen Value, values Value) string {
	lines := []string{}
	for _, key := range orderedKeys(asMap(values)) {
		lines = append(lines, title(key)+": "+display(coreGet(values, key, nil)))
	}
	return strings.Join(lines, "\n")
}
func _core_axgen_apply_field_processors(gen Value, output Value) Value {
	result := cloneMap(asMap(output))
	changed := false
	for _, raw := range asSlice(coreGet(gen, "field_processors", Array())) {
		spec := asMap(raw)
		field := display(coreGet(spec, "field", coreGet(spec, "name", "")))
		if field == "" || coreGet(result, field, nil) == nil {
			continue
		}
		op := display(coreGet(spec, "processor", coreGet(spec, "op", "")))
		value := display(coreGet(result, field, ""))
		switch {
		case op == "uppercase":
			coreSet(result, field, strings.ToUpper(value))
			changed = true
		case op == "lowercase":
			coreSet(result, field, strings.ToLower(value))
			changed = true
		case op == "trim":
			coreSet(result, field, strings.TrimSpace(value))
			changed = true
		case strings.HasPrefix(op, "prefix:"):
			coreSet(result, field, strings.TrimPrefix(op, "prefix:")+value)
			changed = true
		case strings.HasPrefix(op, "suffix:"):
			coreSet(result, field, value+strings.TrimPrefix(op, "suffix:"))
			changed = true
		}
	}
	if changed {
		if g, ok := gen.(*AxGen); ok {
			g.Memory = coreAppend(g.Memory, Object("role", "processor", "output", cloneMap(result), "tags", Array("processor")))
		}
	}
	return result
}
func _core_axgen_run_assertions(gen Value, output Value) (Value, error) {
	out := asMap(output)
	for _, raw := range asSlice(coreGet(gen, "assertions", Array())) {
		assertion := asMap(raw)
		field := display(coreGet(assertion, "field", ""))
		value := output
		if field != "" {
			value = coreGet(out, field, nil)
		}
		message := display(coreGet(assertion, "message", "assertion failed"))
		if returned := coreGet(assertion, "return", nil); returned != nil {
			if b, ok := returned.(bool); ok && !b {
				if coreGet(assertion, "message", nil) == nil {
					return nil, AxError{Category: "runtime", Message: "assertion failed without message"}
				}
				return nil, AxError{Category: "runtime", Message: message}
			}
			if s, ok := returned.(string); ok {
				return nil, AxError{Category: "runtime", Message: s}
			}
		}
		if contains := coreGet(assertion, "contains", nil); contains != nil && !strings.Contains(display(value), display(contains)) {
			return nil, AxError{Category: "runtime", Message: message}
		}
		if equals := coreGet(assertion, "equals", nil); equals != nil && !equal(value, equals) {
			return nil, AxError{Category: "runtime", Message: message}
		}
	}
	return nil, nil
}
func _core_axgen_record_trace(target Value, items ...Value) Value {
	event := Object()
	if len(items) == 1 {
		event = asMap(items[0])
	} else {
		for i, item := range items {
			coreSet(event, fmt.Sprintf("item%d", i), item)
		}
	}
	traces := coreGet(target, "traces", Array())
	traces = coreAppend(traces, event)
	if g, ok := target.(*AxGen); ok {
		g.Traces = traces
	}
	return traces
}
func _core_axgen_should_continue_steps(gen Value, calls Value) Value {
	stops := map[string]bool{}
	for _, item := range asSlice(coreGet(gen, "stop_functions", Array())) {
		stops[display(item)] = true
	}
	if len(stops) == 0 {
		return true
	}
	for _, raw := range asSlice(calls) {
		fn := coreGet(raw, "function", Object())
		name := display(coreGet(fn, "name", coreGet(raw, "name", "")))
		if stops[name] {
			return false
		}
	}
	return true
}
func _core_axgen_apply_context_cache(values ...Value) Value {
	if len(values) < 2 {
		if len(values) == 1 {
			return values[0]
		}
		return Array()
	}
	gen := values[0]
	rawMessages := asSlice(values[1])
	runtimeOptions := Object()
	if len(values) > 2 {
		runtimeOptions = asMap(values[2])
	}
	messages := Array()
	for _, raw := range rawMessages {
		messages = append(messages, cloneValue(raw))
	}
	options := _core_map_merge(coreGet(gen, "options", Object()), runtimeOptions)
	contextCache := coreGet(options, "context_cache", coreGet(options, "contextCache", nil))
	if !coreTruthy(contextCache) || coreTruthy(coreGet(options, "ignore_cache_breakpoints", false)) {
		return messages
	}
	if len(messages) > 0 {
		first := asMap(messages[0])
		coreSet(first, "cache", true)
		messages[0] = first
	}
	breakpoint := "after_examples"
	if cacheMap, ok := contextCache.(map[string]Value); ok {
		breakpoint = display(coreGet(cacheMap, "breakpoint", coreGet(cacheMap, "cache_breakpoint", coreGet(cacheMap, "cacheBreakpoint", breakpoint))))
	}
	if breakpoint == "" || breakpoint == "after_examples" || breakpoint == "afterExamples" {
		for i := len(messages) - 2; i >= 0; i-- {
			msg := asMap(messages[i])
			role := display(coreGet(msg, "role", ""))
			if role == "assistant" || role == "tool" {
				coreSet(msg, "cache", true)
				messages[i] = msg
				break
			}
		}
	}
	return messages
}
func _core_axgen_memory_add_request(target Value, request Value) Value {
	memory := coreGet(target, "memory", Array())
	memory = coreAppend(memory, Object("role", "request", "messages", request, "tags", Array()))
	if g, ok := target.(*AxGen); ok {
		g.Memory = memory
	}
	return memory
}
func axMemoryResponseMeaningful(response Value) bool {
	switch response.(type) {
	case []Value, []string, *AxArray:
		for _, item := range asSlice(response) {
			if axMemoryResponseMeaningful(item) {
				return true
			}
		}
		return false
	}
	m := asMap(response)
	if len(m) == 0 {
		return coreTruthy(response)
	}
	if content := coreGet(m, "content", nil); content != nil && strings.TrimSpace(display(content)) != "" {
		return true
	}
	for _, key := range []string{"function_calls", "functionCalls", "tool_calls", "toolCalls", "thought_blocks", "thoughtBlocks"} {
		if len(asSlice(coreGet(m, key, nil))) > 0 {
			return true
		}
	}
	return coreGet(m, "audio", nil) != nil
}
func _core_axgen_memory_add_response(target Value, values ...Value) Value {
	memory := coreGet(target, "memory", Array())
	response := Value(nil)
	if len(values) > 1 {
		response = values[1]
	} else if len(values) > 0 {
		response = values[0]
	}
	if !axMemoryResponseMeaningful(response) {
		return memory
	}
	entry := Object("role", "assistant", "response", response, "tags", Array())
	memory = coreAppend(memory, entry)
	if g, ok := target.(*AxGen); ok {
		g.Memory = memory
	}
	return memory
}
